/* techniques q13 (60 mục) — R6 sửa lỗi - gop trung 2026-07-14 - gop trung 2026-07-15 - gop trung 2026-07-15 - gop trung 2026-07-16 */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q13"]=window.__LIBQ["tien-nghich"]["q13"]||{};window.__LIBQ["tien-nghich"]["q13"]["techniques"]={"updatedAt":"2026-07-13","count":60,"techniques":[{"id":"la-thien-huyen-kinh","name":"La Thiên Huyễn Kính","cn":"罗天幻镜","loai":"than-thong","loaiLabel":"Thần thông / Trận pháp hợp lực","phamCap":"Không rõ","hePhai":"La Thiên Tinh Vực","soHuu":["Lỗ Phu Tử","Viêm Lôi Tử","Liệt Vân Tử","Huyết Thần Tử","Hướng Vân Đông"],"blurb":"Trận pháp hợp lực do Lỗ Phu Tử truyền thụ, bốn người bấm quyết tạo ra tấm gương hư ảo màu trắng như mặt nước, có thể viễn cảm quan sát tinh không.","detail":"Bốn tu sĩ đồng thời bấm quyết tạo ra tấm gương hư ảo màu trắng giống như mặt nước, có thể chiếu hiện hình ảnh kẻ ở xa trong tinh không. Bị Vương Lâm phát hiện và dùng lôi đồ phá hủy từ xa, lôi đình kinh thiên từ bên trong tấm kính tràn ra khiến kính vỡ tan, bốn người thi triển đều phun máu.","nguonGoc":"Lỗ Phu Tử truyền thụ cho bốn người","thuocTinh":"Viễn cảm","congNang":["Viễn cảm quan sát tinh không, chiếu hiện hình ảnh mục tiêu ở xa"],"nguoiTu":[{"ten":"Viêm Lôi Tử","tuChuong":"@c1387","tangDatToi":"Viên mãn","trangThai":"dang-tu"},{"ten":"Liệt Vân Tử","tuChuong":"@c1387","tangDatToi":"Viên mãn","trangThai":"dang-tu"},{"ten":"Huyết Thần Tử","tuChuong":"@c1387","tangDatToi":"Viên mãn","trangThai":"dang-tu"},{"ten":"Hướng Vân Đông","tuChuong":"@c1387","tangDatToi":"Viên mãn","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1387","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu xuất hiện và bị phá hủy","text":"Lỗ Phu Tử ra lệnh bốn người bày La Thiên Huyễn Kính để quan sát kẻ xâm nhập La Thiên Tinh Vực. Tấm gương chiếu ra hình ảnh Vương Lâm nhưng bị hắn dùng lôi đồ phá hủy từ xa, bốn người phun máu.","anchor":"Bốn người các ngươi hãy bày ra La Thiên Huyễn Kính, lão phu muốn xem người này là ai"}]},"capNhatToi":"@c1387","nguon":["@c1387"]},{"id":"tu-hon","name":"Tu hồn","cn":"修魂","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Tạ Thanh"],"blurb":"Tu hồn là con đường tu hành do Tạ Thanh tự minh ngộ từ cơ hội Vương Lâm ban cho, hoàn toàn bỏ qua thần thông, chỉ chuyên tu ý cảnh đạo niệm thuần túy, lấy hồn nhập mệnh. Đây là phương pháp không tồn tại sẵn trong thế gian, được Vương Lâm nhận xét tương tự luyện thể cực đoan của bộ tộc Cổ Thần nhưng ở khía cạnh hồn phách.","detail":"Tu hồn là phương pháp tu hành độc nhất vô nhị, không có tiền lệ trong thế gian, do Tạ Thanh tự mình minh ngộ sau tám trăm năm tĩnh tọa chỉ tu ý cảnh. Cơ duyên của con đường này bắt nguồn từ cơ hội mà Vương Lâm ban cho Tạ Thanh. Người tu theo phương pháp này bỏ hết mọi công pháp thần thông, không có nguyên thần, nguyên anh, nội thần, thân thể trở nên cực kỳ yếu ớt, nhưng bù lại hồn phách tràn ngập sức sống vô biên. Vương Lâm khi nhận ra bản chất tu hành của Tạ Thanh đã đặt tên gọi tu hồn — lấy hồn nhập mệnh, đồng thời nhận xét cách tu này giống như phiên bản cực đoan của luyện thể bộ tộc Cổ Thần, chỉ khác là áp dụng cho hồn phách thay vì thể xác. Yếu quyết để hoàn thành con đường tu hồn là phản phác quy chân: bỏ được thân thể, quên hết pháp thuật, chỉ còn lại một đạo hồn phách duy nhất. Ý c","thuocTinh":"Hồn phách / Ý cảnh","nguonGoc":"Tạ Thanh tự minh ngộ từ cơ hội Vương Lâm ban cho","yeuCau":"Bỏ hoàn toàn thần thông pháp thuật, chỉ tu ý cảnh","uyLuc":"Ý cảnh đạo niệm đạt Tịnh Niết sơ khuy quy tắc, khiến tu sĩ Khuy Niết cũng không địch nổi về phương diện ý cảnh.","dacDiem":"Không có nguyên thần, nguyên anh, nội thần; thân thể cực yếu nhưng hồn phách sức sống vô biên. Yếu quyết hoàn thành là phản phác quy chân — bỏ được thân thể, quên hết pháp thuật, chỉ còn một đạo hồn phách.","trangThai":"Tạ Thanh đang tu, chưa hoàn toàn minh ngộ","congNang":["Chỉ chuyên tu ý cảnh đạo niệm thuần túy, bỏ qua hoàn toàn thần thông pháp thuật, lấy hồn nhập mệnh @c1389","Hồn phách tích tụ sức sống vô biên dù thân thể cực kỳ yếu ớt","Ý cảnh đạo niệm có thể đạt cảnh giới Tịnh Niết, sơ khuy quy tắc, áp chế tu sĩ Khuy Niết về mặt ý cảnh"],"nguoiTu":[{"ten":"Tạ Thanh","tuChuong":"@c1389","tangDatToi":"Ý cảnh Tịnh Niết sơ khuy quy tắc","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1389","loai":"xuat-hien","importance":"major","giaiDoan":"Vương Lâm nhận ra và đặt tên phương pháp tu hồn","text":"Vương Lâm nhận ra Tạ Thanh ngồi tám trăm năm chỉ tu ý cảnh, gọi đây là tu hồn — lấy hồn nhập mệnh, phương pháp không tồn tại trong thế gian.","anchor":"Còn Tạ Thanh lại hoàn toàn bỏ qua thần thông, chỉ tu ý cảnh"}]},"capNhatToi":"@c1389","nguon":["@c1389"]},{"id":"phan-phac-quy-chan","name":"Phản phác quy chân","cn":"返璞归真","loai":"khac","loaiLabel":"Triết lý đạo pháp","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Vương Lâm"],"blurb":"Triết lý đạo pháp Vương Lâm giảng cho Tạ Thanh: đem bản thân dung nhập vào thiên địa, thoát khỏi hạn chế vạn vật, trở thành một phần của thiên địa.","detail":"Vương Lâm dùng ví dụ về núi, biển, cây cỏ — không thứ gì ngăn cản nước mưa — để giảng lý: đem bản thân dung nhập vào từng cái cây ngọn cỏ, trở thành một phần của thiên địa, thoát khỏi hạn chế vạn vật. Là yếu quyết để Tạ Thanh hoàn toàn minh ngộ tu hồn. Vương Lâm tự nhận năm đó cũng tưởng hiểu bốn chữ này nhưng sau khi trải nhiều việc mới thực sự giác ngộ.","congNang":["Dung nhập bản thân vào thiên địa, bỏ qua thân thể và pháp thuật"],"tabs":{"tienTrinh":[{"chuong":"@c1389","loai":"xuat-hien","importance":"normal","giaiDoan":"Vương Lâm giảng cho Tạ Thanh","text":"Vương Lâm giảng lý phản phác quy chân cho Tạ Thanh, phá tan pháp thuật chặn mưa vô thức của hắn, dặn phải bỏ hết thân thể và pháp thuật.","anchor":"phản phác quy chân, đó là phải đem bản thân dung nhập vào trong từng cái cây ngọn cỏ"}]},"capNhatToi":"@c1389","nguon":["@c1389"]},{"id":"tinh-ton-that-kiep-tran","name":"Tinh Tổn Thất Kiếp Trận","cn":"星陨七劫阵","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Truyền thuyết","hePhai":"Không rõ","soHuu":[],"blurb":"Trận pháp uy lực kinh thiên trong truyền thuyết, cần dùng tu chân tinh phù hợp yêu cầu để tạo thành. La Thiên lão tổ hạ lệnh Lôi Tiên Điện tìm tinh cầu lập trận.","detail":"Trận pháp uy lực kinh thiên tồn tại trong truyền thuyết, yêu cầu thu thập nhiều tu chân tinh phù hợp để bày trận. La Thiên lão tổ hạ lệnh cho Lôi Tiên Điện tìm kiếm tu chân tinh, nhóm tu sĩ nhắm Thanh Linh Tinh nhưng bị kiếm ý vũ kiếm Vương Lâm đẩy lùi.","congNang":["Uy lực kinh thiên, cần tu chân tinh để bày trận"],"tabs":{"tienTrinh":[{"chuong":"@c1389","loai":"xuat-hien","importance":"normal","giaiDoan":"Lần đầu được nhắc tới","text":"Nhóm Lôi Tiên Điện phụng mệnh La Thiên lão tổ tìm tu chân tinh phù hợp để tạo thành trận pháp này.","anchor":"tạo thành Tinh Tổn Thất Kiếp Trận uy lực kinh thiên trong truyền thuyết"}]},"capNhatToi":"@c1389","nguon":["@c1389"]},{"id":"cuu-sinh-huyet-anh-thuat","name":"Cửu sinh huyết anh thuật","cn":"九生血婴术","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lưu gia (Đông Lâm Tinh)","soHuu":["Lưu gia"],"blurb":"Thần thông độc nhất của Lưu gia trên Đông Lâm Tinh, dung hợp với pháp bảo, uy lực kinh thiên. Từ khi sáng tạo tới nay chỉ dùng có một lần nhưng khiến toàn bộ sinh linh La Thiên Tinh Vực rên xiết.","detail":"Thần thông chế pháp bảo đặc thù của Lưu gia — dung hợp pháp bảo với bản thân, uy lực kinh thiên. Kể từ khi được sáng tạo, chỉ thi triển đúng một lần, lần đó khiến toàn bộ sinh linh trong La Thiên Tinh Vực rên xiết, chẳng khác gì ngày tận thế.","thuocTinh":"Dung hợp pháp bảo","nguonGoc":"Do Lưu gia (Đông Lâm Tinh) sáng tạo","uyLuc":"Kinh thiên, một lần thi triển khiến toàn La Thiên Tinh Vực rên xiết như ngày tận thế","dacDiem":"Thần thông dung hợp với pháp bảo","congNang":["Dung hợp pháp bảo với bản thân, uy lực kinh thiên"],"nguoiTu":[{"ten":"Lưu gia","tuChuong":"@c1390","tangDatToi":"","trangThai":"đang nắm giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1390","loai":"xuất hiện","importance":"normal","giaiDoan":"Hé lộ danh tiếng","text":"Được giới thiệu là thần thông độc nhất của Lưu gia trên Đông Lâm Tinh, dung hợp pháp bảo, uy lực kinh thiên, từ khi sáng tạo chỉ dùng một lần nhưng khiến toàn La Thiên Tinh Vực rên xiết.","anchor":"Cửu sinh huyết anh thuật lại càng là thần thông dung hợp với pháp bảo, uy lực kinh thiên"}]},"nguon":["@c1390"]},{"id":"tran-phap-lien-hop-lu-gia","name":"Trận pháp liên hợp Lữ gia","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Lữ gia (Đông Lâm Tinh)","soHuu":["Lữ gia"],"blurb":"Trận pháp cấm chế của hơn một vạn tu sĩ Lữ gia ở phía bắc Đông Lâm Tinh, mấy chục lão già phun máu ngưng tụ thành huyết ảnh.","detail":"Hơn một vạn tu sĩ Lữ gia ngồi chi chít dưới đất hợp thành trận pháp cấm chế khổng lồ, mấy chục lão già khoanh chân ngồi giữa không trung bấm quyết liên tục phun máu tươi ngưng tụ thành huyết ảnh bao phủ phía bắc Đông Lâm Tinh để nghênh chiến Vương Lâm.","congNang":["Tạo trận pháp cấm chế phòng thủ quy mô lớn","Phun máu ngưng tụ thành huyết ảnh chiến đấu"],"tabs":{"tienTrinh":[{"chuong":"@c1391","loai":"xuất hiện","importance":"normal","giaiDoan":"Kích hoạt nghênh chiến Vương Lâm","text":"Hơn một vạn tu sĩ Lữ gia bày trận cấm chế ở phía bắc Đông Lâm Tinh, mấy chục lão già phun máu tạo huyết ảnh để ngăn Vương Lâm tiến vào.","anchor":"mấy chục lão già khoanh chân ngồi ở giữa không trung, hai tay nhanh chóng bấm quyết, liên tục phun ra máu tươi"}]},"nguon":["@c1391"]},{"id":"tran-phap-dam-mau-hua-gia","name":"Trận pháp đầm máu Hứa gia","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Hứa gia (Đông Lâm Tinh)","soHuu":["Hứa gia (Đông Lâm Tinh)"],"blurb":"Trận pháp sát khí điên cuồng của gần một vạn tu sĩ Hứa gia ở phía nam Đông Lâm Tinh, triển khai quanh đầm máu rộng ngàn trượng.","detail":"Gần một vạn tu sĩ Hứa gia lần lượt đi vào đầm máu rộng ngàn trượng ở phía nam Đông Lâm Tinh, bên trong có sát khí điên cuồng lao ra, tạo thành trận pháp phòng thủ nghênh chiến Vương Lâm.","congNang":["Tạo sát trận phòng thủ từ đầm máu ngàn trượng chứa sát khí"],"tabs":{"tienTrinh":[{"chuong":"@c1391","loai":"xuất hiện","importance":"normal","giaiDoan":"Kích hoạt nghênh chiến Vương Lâm","text":"Gần một vạn tu sĩ Hứa gia triển khai quanh đầm máu ngàn trượng ở phía nam Đông Lâm Tinh để ngăn Vương Lâm.","anchor":"ở chính giữa có một cái đầm máu rộng ngàn trượng, bên trong cái đầm này có một luồng sát khí điên cuồng lao ra"}]},"nguon":["@c1391"]},{"id":"tran-phap-hoa-huong-duong-luu-gia","name":"Trận pháp hoa hướng dương Lưu gia","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Lưu gia (Đông Lâm Tinh)","soHuu":["Lưu gia (Đông Lâm Tinh)"],"blurb":"Trận pháp phối hợp pháp bảo của tu sĩ Lưu gia ở phía đông Đông Lâm Tinh, cứ bảy người một nhóm kết hợp với pháp bảo cao mấy chục trượng tạo đồ án hình hoa hướng dương.","detail":"Tu sĩ Lưu gia ở phía đông Đông Lâm Tinh cứ bảy người hợp thành một nhóm, bên cạnh mỗi nhóm có một pháp bảo cao mấy chục trượng hình dáng khác nhau phát ra ánh sáng vàng, toàn bộ kết hợp thành đồ án hình hoa hướng dương trong phạm vi ngàn dặm để nghênh chiến Vương Lâm.","congNang":["Trận pháp phối hợp nhóm 7 người kết hợp pháp bảo tạo đồ án hoa hướng dương phòng thủ"],"tabs":{"tienTrinh":[{"chuong":"@c1391","loai":"xuất hiện","importance":"normal","giaiDoan":"Kích hoạt nghênh chiến Vương Lâm","text":"Tu sĩ Lưu gia cứ bảy người một nhóm phối hợp pháp bảo tạo đồ án hoa hướng dương phạm vi ngàn dặm ở phía đông Đông Lâm Tinh.","anchor":"toàn bộ những tu sĩ của Lưu gia này kết hợp thành một đồ án hình hoa hướng dương"}]},"nguon":["@c1391"]},{"id":"than-chan","name":"Thần Chấn","cn":"神震","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Vượt bước thứ hai","hePhai":"Đạo Cổ / Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Thần Chấn là quyền pháp tấn công tầm xa dung hợp sức mạnh thất tinh Cổ Thần với Đạo Cổ truyền thừa, do Vương Lâm thi triển. Một quyền đánh ra tạo nắm tay hư ảo mấy vạn trượng với sức công phá kinh thiên, đủ sức phá hủy trận pháp thượng cổ và nát tiểu tinh trong tám nhịp thở.","detail":"Thần Chấn là quyền thuật được Vương Lâm kích phát bằng cách khai hoạt bảy tinh điểm Cổ Thần trên mi tâm, giải phóng khí tức Đạo Cổ rồi nắm tay đánh ra. Nắm tay hư ảo mấy vạn trượng lao tới mục tiêu, uy lực đủ phá vỡ hơn chín ngàn vạn tầng hào quang trận pháp thượng cổ của Đông Lâm Tinh, đánh nát mấy chục tiểu tinh, tiêu diệt huyết ảnh trận linh và tạo hố sâu mấy vạn trượng trên bề mặt Đông Lâm Tinh. Toàn bộ quá trình phá hủy này chỉ diễn ra trong tám nhịp thở, trong khi Lỗ Phu Tử — cường giả bước thứ ba — tự đánh giá bản thân cần tới hai mươi nhịp thở mới làm được điều tương tự. Chỉ riêng sức mạnh thân thể thất tinh Cổ Thần đã đủ để giao chiến với cao thủ bước thứ ba, và Thần Chấn chính là thể hiện cực đoan của sức mạnh ấy khi kết hợp cùng Đạo Cổ truyền thừa. Tại chương @c1392, Vương Lâm đ","congNang":["Tạo nắm tay hư ảo mấy vạn trượng tấn công tầm xa với sức công phá cực lớn @c1392","Dung hợp sức mạnh thất tinh Cổ Thần và khí tức Đạo Cổ truyền thừa thành một kích @c1392","Phá vỡ hơn chín ngàn vạn tầng hào quang trận pháp thượng cổ @c1392","Đánh nát mấy chục tiểu tinh, tạo hố sâu mấy vạn trượng trên bề mặt hành tinh @c1392","Tiêu diệt huyết ảnh trận linh @c1392"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1392","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1392","loai":"thi triển","importance":"major","giaiDoan":"Thi triển lần đầu","text":"Vương Lâm đánh ra một quyền Thần Chấn dung hợp thất tinh Cổ Thần và Đạo Cổ truyền thừa, phá hủy toàn bộ đại trận thượng cổ Đông Lâm Tinh trong tám nhịp thở.","anchor":"Tám nhịp thở! Từ lúc Vương Lâm đánh ra một quyền Thần Chấn, trận pháp hào quang tan vỡ, toàn bộ tiểu tinh đều nổ tung"}]},"nguon":["@c1392"],"uyLuc":"Một quyền phá vỡ hơn chín ngàn vạn tầng hào quang trận pháp thượng cổ Đông Lâm Tinh, đánh nát mấy chục tiểu tinh và tạo hố sâu mấy vạn trượng chỉ trong tám nhịp thở — nhanh hơn gấp bội so với năng lực tự đánh giá của cường giả bước thứ ba Lỗ Phu Tử.","dacDiem":"Quyền pháp kích phát thông qua bảy tinh điểm Cổ Thần trên mi tâm, kết hợp Đạo Cổ truyền thừa; biểu hiện là nắm tay hư ảo mấy vạn trượng lao tới mục tiêu, mang uy lực thuần túy từ nhục thân Cổ Thần cộng hưởng Đạo Cổ."},{"id":"tran-phap-thuong-co-dong-lam-tinh","name":"Trận pháp thượng cổ Đông Lâm Tinh","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Mạnh nhất bước thứ hai","hePhai":"Lữ gia","soHuu":["Lữ gia"],"blurb":"Trận pháp thượng cổ Đông Lâm Tinh là đại trận phòng thủ lưu truyền từ thời thượng cổ, do Lữ gia nuôi dưỡng trận linh suốt mấy vạn năm, kết hợp ba trận pháp tạo thành chín ngàn chín trăm chín mươi chín vạn tầng hào quang bao vây toàn bộ Đông Lâm Tinh. Được xác nhận là thần thông phòng thủ mạnh nhất bước thứ hai, nhưng cuối cùng bị Vương Lâm phá hủy hoàn toàn chỉ trong tám nhịp thở bằng quyền Thần Chấn.","detail":"Trận pháp thượng cổ Đông Lâm Tinh là hệ thống phòng thủ quy mô tinh cầu gồm ba trận pháp hợp nhất: Trận hóa thiên mạc, Cấm ma thiên tiên và Trận cấm bát phương. Đại trận này được Lữ gia lưu truyền từ thời thượng cổ và nuôi dưỡng trận linh suốt mấy vạn năm, cần hàng ngàn tu sĩ trên mấy chục tiểu tinh đồng thời vận hành mới có thể phát huy toàn lực. Khi kích hoạt, đại trận tạo ra chín ngàn chín trăm chín mươi chín vạn tầng hào quang bao vây Đông Lâm Tinh, uy lực đủ để ngay cả tu sĩ có tu vi Thiên Nhân Đệ Ngũ Suy cũng không thể đơn độc phá vỡ, và cường giả bước thứ ba như Lỗ Phu Tử cũng cần tới hai mươi nhịp thở. Tại mốc @c1392, Lữ gia kích hoạt toàn bộ đại trận nhằm chống lại Vương Lâm, tuy nhiên Vương Lâm sử dụng quyền Thần Chấn phá hủy hoàn toàn đại trận chỉ trong tám nhịp thở.","congNang":["Tạo hào quang phòng thủ nhiều tầng (chín ngàn chín trăm chín mươi chín vạn tầng) bao vây toàn bộ tinh cầu Đông Lâm Tinh @c1392","Cần trận linh được nuôi dưỡng mấy vạn năm cùng hàng ngàn tu sĩ trên mấy chục tiểu tinh đồng thời vận hành để phát huy toàn lực @c1392"],"trangThai":"bi-huy-diet","capNhatToi":"@c1392","tabs":{"tienTrinh":[{"chuong":"@c1392","loai":"xuất hiện","importance":"major","giaiDoan":"Kích hoạt và bị phá hủy","text":"Lữ gia kích hoạt toàn bộ đại trận thượng cổ chống Vương Lâm, tạo hơn chín ngàn vạn tầng hào quang. Bị Vương Lâm phá hủy hoàn toàn trong tám nhịp thở bằng quyền Thần Chấn.","anchor":"trận pháp này là thần thông mạnh nhất của bước thứ hai, cho dù là tu vi Thiên Nhân Đệ Ngũ Suy muốn một mình phá vỡ trận pháp này cũng hoàn toàn không có khả năng"}]},"nguon":["@c1392"],"uyLuc":"Được xác nhận là thần thông phòng thủ mạnh nhất bước thứ hai; tu sĩ Thiên Nhân Đệ Ngũ Suy không thể đơn độc phá vỡ, cường giả bước thứ ba như Lỗ Phu Tử cần hai mươi nhịp thở mới có thể công phá, nhưng bị Vương Lâm dùng quyền Thần Chấn phá hủy hoàn toàn chỉ trong tám nhịp thở @c1392.","dacDiem":"Hệ thống phòng thủ quy mô tinh cầu hợp nhất từ ba trận pháp (Trận hóa thiên mạc, Cấm ma thiên tiên, Trận cấm bát phương), đòi hỏi thời gian nuôi dưỡng trận linh cực dài tính bằng vạn năm và nhân lực vận hành khổng lồ trải trên nhiều tiểu tinh."},{"id":"hien-te-huyet-anh-ngung-tu-tran-linh","name":"Hiến tế huyết ảnh, ngưng tụ trận linh","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật hiến tế","phamCap":"","hePhai":"Lữ gia","soHuu":["Lữ gia"],"blurb":"Bí thuật hiến tế của Lữ gia: gần một vạn tu sĩ phun máu, mấy chục lão già nổ tung hóa sương máu tạo thành huyết ảnh trận linh mang khí tức trận pháp cấm chế.","detail":"Gần một vạn tu sĩ Lữ gia phun máu tươi, ngưng tụ lên mấy chục lão già ngồi chính giữa. Các lão già thân thể bành trướng như quả huyết cầu rồi nổ tung, hóa sương máu ngưng tụ thành huyết ảnh mang khí tức trận pháp cấm chế. Huyết ảnh lao lên đối kháng quyền Thần Chấn của Vương Lâm nhưng bị đánh nổ tung ngay lập tức, hóa thành mưa máu.","congNang":["Tạo trận linh từ hiến tế sinh mạng để kháng cự tấn công"],"trangThai":"bi-huy-diet","tabs":{"tienTrinh":[{"chuong":"@c1392","loai":"thi triển","importance":"normal","giaiDoan":"Thi triển và thất bại","text":"Lữ gia hiến tế gần một vạn tu sĩ tạo huyết ảnh trận linh đối kháng Thần Chấn nhưng bị đánh nổ tung ngay lập tức.","anchor":"huyết ảnh kia dưới một quyền này trực tiếp nổ tung, hóa thành vô số mưa máu tứ tán từ trên không trung rơi xuống"}]},"nguon":["@c1392"]},{"id":"huyet-quy-thuat","name":"Huyết Quỳ Thuật","cn":"血葵术","loai":"than-thong","loaiLabel":"Thần thông (cấm thuật tập thể)","phamCap":"Gần bước thứ ba Không Niết Sơ Kỳ","hePhai":"Lưu gia (Đông Lâm Tinh)","soHuu":["Lưu gia"],"blurb":"Huyết Quỳ Thuật là cấm thuật riêng của Lưu gia Đông Lâm Tinh, đòi hỏi gần một vạn tu sĩ đồng loạt hy sinh tính mạng để dung hợp thần chú, tạo ra cột sáng hoàng kim huyết quang vạn trượng chứa thân ảnh chiến binh không đầu mặc giáp cầm trường thương. Uy lực gần đạt trình độ bước thứ ba Không Niết Sơ Kỳ, vượt xa giới hạn tu sĩ Thiên Nhân Đệ Ngũ Suy.","detail":"Huyết Quỳ Thuật là cấm thuật gia truyền của Lưu gia tại Đông Lâm Tinh. Khi thi triển, gần một vạn tu sĩ Lưu gia đồng loạt khoanh chân bấm quyết niệm thần chú, cơ thể tỏa ra hương hoa dị thường, trên mặt đất hình thành bông hoa hướng dương vàng khổng lồ. Chính giữa bông hoa là đầu của gần vạn tu sĩ — đầu đồng loạt vỡ tung, thần chú dung hợp tạo ra cột sáng hoàng kim kèm huyết quang cao vạn trượng, bên trong hiển hiện thân ảnh không đầu mặc áo giáp cầm trường thương. Cái giá của thuật này là toàn bộ tu sĩ tham gia đều chết, thực chất là hy sinh vạn mạng đổi lấy một đòn tấn công cấp bước thứ ba. Khi đối đầu Vương Lâm, Huyết Quỳ Thuật bị Vương Lâm một chưởng đỡ lại rồi phá hủy; bản thân Vương Lâm cũng tiếc nuối vì thần thông này đã bị hủy mất (@c1393).","thuocTinh":"Huyết, Hy sinh","nguonGoc":"Cấm thuật riêng của Lưu gia Đông Lâm Tinh","yeuCau":"Cần gần vạn tu sĩ đồng loạt thi triển, toàn bộ hy sinh tính mạng","uyLuc":"Uy lực gần đạt trình độ bước thứ ba Không Niết Sơ Kỳ, vượt quá giới hạn tu sĩ Thiên Nhân Đệ Ngũ Suy, song bị Vương Lâm một chưởng đỡ và phá hủy (@c1393).","dacDiem":"Triệu hồi thân ảnh không đầu mặc giáp cầm trường thương trong cột sáng hoàng kim huyết quang; trước khi phát động, gần vạn tu sĩ hình thành bông hoa hướng dương vàng khổng lồ trên mặt đất, đầu vỡ tung làm nhiên liệu cho thuật; đại giá là toàn bộ người tham gia chết, không thể đảo ngược.","trangThai":"Đã bị phá hủy (bị Vương Lâm phá)","congNang":["Cấm thuật hy sinh tính mạng gần một vạn tu sĩ, dung hợp thần chú tạo đòn tấn công cấp bước thứ ba (@c1393)","Triệu hồi thân ảnh chiến binh không đầu mặc áo giáp cầm trường thương trong cột sáng hoàng kim huyết quang vạn trượng (@c1393)"],"nguoiTu":[{"ten":"Lưu gia (toàn bộ tu sĩ)","tuChuong":"@c1393","tangDatToi":"Toàn diệt khi thi triển","trangThai":"tu-vong"}],"tabs":{"tienTrinh":[{"chuong":"@c1393","loai":"thi triển","importance":"major","giaiDoan":"Thi triển duy nhất — Lưu gia toàn diệt","text":"Gần một vạn tu sĩ Lưu gia đồng loạt thi triển Huyết Quỳ Thuật, đầu vỡ tung dung hợp thần chú tạo cột sáng vạn trượng chứa thân ảnh không đầu mặc giáp cầm trường thương, uy lực gần bằng Không Niết Sơ Kỳ bước thứ ba. Bị Vương Lâm một chưởng đỡ, lực phản chấn tách phần phía đông Đông Lâm Tinh, toàn bộ Lưu gia tử vong.","anchor":"hàng vạn chiếc đầu đồng loạt vỡ tung, cùng với những thần chú kia dung hợp với nhau"}]},"capNhatToi":"@c1393","nguon":["@c1393"]},{"id":"huyen-than-thuat","name":"Huyễn Thần Thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Lão già mặc kim bào (Đông Lâm gia)"],"blurb":"Thần thông tạo hình tượng huyễn ảo khổng lồ có thể chiến đấu, do lão già kim bào Đông Lâm gia thi triển.","detail":"Tạo ra hình tượng người khổng lồ mặc kim giáp cao mấy ngàn trượng cực kỳ chân thật, có khả năng vung đại kiếm ngàn trượng chiến đấu. Bị Vương Lâm dùng một chỉ kết hợp huyết kiếm phá vỡ, bức người thi triển lộ bản thể.","congNang":["Tạo hình ảo thần khổng lồ có thể chiến đấu","Che giấu bản thể người thi triển"],"nguoiTu":[{"ten":"Lão già mặc kim bào (Đông Lâm gia)","tuChuong":"@c1394","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1394","loai":"thi triển","importance":"normal","giaiDoan":"Lão già kim bào thi triển, bị Vương Lâm phá","text":"Lão già kim bào Đông Lâm gia thi triển Huyễn Thần Thuật tạo người khổng lồ kim giáp ngàn trượng, tuyên đọc ba tội trạng của Vương Lâm và vung đại kiếm vàng tấn công. Bị Vương Lâm một chỉ phá tan đại kiếm, huyết kiếm đâm xuyên phá vỡ hình tượng, bức lộ bản thể.","anchor":"Vương Lâm đã phá vỡ Huyễn Thần Thuật của hắn, khiến cho hắn không thể không lộ ra bản thể"}]},"nguon":["@c1394"]},{"id":"thuat-truyen-cong","name":"Thuật truyền công","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thuật truyền nguyên lực vô biên cùng cảm ngộ cả đời vào cơ thể người khác, giúp đối phương đột phá nhiều bậc tu vi liên tiếp. Cực kỳ tiêu hao, ngay cả Vương Lâm cũng rất khó thực hiện lại lần nữa.","detail":"Vương Lâm thi triển thuật truyền công, truyền nguyên lực vô biên cùng một phần cảm ngộ cả đời tu hành vào cơ thể Tây Tử Phượng, khiến tu vi nàng từ Dương Thực đột phá liên tiếp qua Khuy Niết tới Tinh Tịnh Niết. Sau khi truyền công, Vương Lâm đặt ba đạo phong ấn áp chế tu vi bạo tăng để nàng từ từ tiêu hóa. Thuật này tiêu hao cực lớn, khó có thể thực hiện lần thứ hai.","thuocTinh":"Nguyên lực, cảm ngộ","nguonGoc":"","yeuCau":"Tu vi cực cao","uyLuc":"Nâng tu vi đối phương nhiều đại cảnh giới liên tiếp, từ Dương Thực đột phá qua Khuy Niết tới Tinh Tịnh Niết.","dacDiem":"Cực kỳ tiêu hao, khó làm lại lần nữa ngay cả với tu vi như Vương Lâm.","congNang":["Truyền nguyên lực cùng cảm ngộ cả đời vào cơ thể người khác, giúp đối phương đột phá nhiều bậc tu vi liên tiếp @c1398"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1398","tangDatToi":"","trangThai":"dang-co"}],"trangThai":"dang-co","capNhatToi":"@c1398","tabs":{"tienTrinh":[{"chuong":"@c1398","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Vương Lâm dùng thuật truyền công truyền nguyên lực vô biên cùng phần cảm ngộ cả đời vào cơ thể Tây Tử Phượng, giúp tu vi nàng đột phá từ Dương Thực tới Tinh Tịnh Niết, đặt ba đạo phong ấn áp chế.","anchor":"Thuật truyền công này, ngay cả với tu vi như của Vương Lâm. muốn làm lại cũng rất khó khăn"}]},"nguon":["@c1398"]},{"id":"tinh-tran-loi-tien-dien","name":"Tinh trận khổng lồ Lôi Tiên Điện","loai":"bi-thuat","loaiLabel":"Trận pháp","soHuu":["Lôi Tiên Điện"],"blurb":"Trận pháp phòng thủ quy mô lớn do mấy trăm tu chân tinh tạo thành, có vòng xoáy ở trung tâm. Mười một đạo kiếm khí Vương Lâm xâm nhập giết mười một người bên trong mà không phá được trận.","detail":"Trận pháp phòng thủ do mấy trăm tu chân tinh tạo thành, có vòng xoáy khổng lồ ở trung tâm nơi Lỗ Phu Tử trấn giữ. Nhiều tu sĩ đang nhanh chóng qua lại bố trí gia cố, chuẩn bị cho chiến tranh. Dù quy mô khổng lồ nhưng mười một đạo kiếm khí của Vương Lâm vẫn xâm nhập được bên trong giết mười một mục tiêu.","congNang":["Phòng thủ quy mô tinh vực, bao phủ mấy trăm tu chân tinh"],"tabs":{"tienTrinh":[{"chuong":"@c1399","loai":"xuất hiện","importance":"normal","giaiDoan":"Đang gia cố chuẩn bị chiến tranh","text":"Mấy trăm tu chân tinh tạo thành tinh trận khổng lồ, nhiều tu sĩ đang bố trí gia cố. Mười một đạo kiếm khí Vương Lâm xâm nhập giết mười một người bên trong.","anchor":"ờ trong ngoài trận pháp khổng lồ do mấy trăm tu chân tinh tạo thành có rất nhiều tu sĩ đang nhanh chóng qua lại"}]},"nguon":["@c1399"]},{"id":"phong-bon-nguyen","name":"Phong bổn nguyên","cn":"风本源","loai":"than-thong","loaiLabel":"Bổn nguyên đạo","phamCap":"Bổn nguyên","hePhai":"Phong","soHuu":["Lỗ Phu Tử"],"blurb":"Bổn nguyên đạo của Lỗ Phu Tử, cảm ngộ từ Phong Tiên Giới, đồng tử hiện chín cơn lốc xoáy khi phát động.","detail":"Lỗ Phu Tử từng chịu ơn Phong Tiên Giới, cả đời cảm ngộ phong bổn nguyên. Khi phát động, đồng tử hiện chín cơn lốc xoáy, cuồng phong ầm ầm bộc phát. Được dung nhập vào La Thiên Thụ khiến pháp bảo mang khí tức Không Niết.","thuocTinh":"Phong","nguonGoc":"Cảm ngộ từ Phong Tiên Giới","congNang":["Phát động cuồng phong bổn nguyên","Dung nhập vào pháp bảo tạo khí tức Không Niết"],"nguoiTu":[{"ten":"Lỗ Phu Tử","tuChuong":"@c1401","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1401","loai":"thi triển","importance":"normal","giaiDoan":"Lỗ Phu Tử dùng trong luyện khí","text":"Lỗ Phu Tử dung nhập phong bổn nguyên vào cây đại thụ trong hiệp đấu văn luyện khí, khiến pháp bảo La Thiên Thụ mang khí tức Không Niết.","anchor":"lão phu tuy là người của La Thiên, nhưng đã từng chịu ơn của Phong Tiên Giới, cả đời cảm ngộ phong bổn nguyên"}]},"nguon":["@c1401"]},{"id":"loi-hoa-bon-nguyen","name":"Lôi hỏa bổn nguyên","cn":"雷火本源","loai":"than-thong","loaiLabel":"Bổn nguyên đạo","phamCap":"Bổn nguyên","hePhai":"Lôi Hỏa","soHuu":["Vương Lâm"],"blurb":"Bổn nguyên đạo kết hợp lôi và hỏa của Vương Lâm, có thể triệt tiêu cuồng phong bổn nguyên.","detail":"Khi cuồng phong bổn nguyên của Lỗ Phu Tử quét qua, Vương Lâm dùng lôi hỏa bổn nguyên tràn ngập trong hai mắt, triệt tiêu từng tầng mà thân thể không hề cử động.","thuocTinh":"Lôi Hỏa","congNang":["Triệt tiêu/vô hiệu hóa cuồng phong bổn nguyên"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1401","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1401","loai":"thi triển","importance":"normal","giaiDoan":"Vương Lâm vô hiệu cuồng phong Lỗ Phu Tử","text":"Vương Lâm dùng lôi hỏa bổn nguyên triệt tiêu từng tầng cuồng phong bổn nguyên của Lỗ Phu Tử trong lúc luyện khí, thân thể bất động.","anchor":"hai mắt lập tức liền có lôi hỏa bổn nguyên tràn ngập, từng tầng triệt tiêu, thân thể không hề cử động"}]},"nguon":["@c1401"]},{"id":"dau-van-ba-hiep","name":"Đấu văn ba hiệp","loai":"khac","loaiLabel":"Quy tắc giao đấu","soHuu":[],"blurb":"Hình thức giao đấu do Lỗ Phu Tử đề xuất gồm ba hiệp: luyện khí, đấu đạo niệm, đấu một thức thần thông.","detail":"Thay vì sinh tử chiến có thể kích động Phong Giới Đại Trận, Lỗ Phu Tử đề nghị đấu văn ba hiệp: hiệp một — luyện khí (hoặc luyện đan, luyện hồn), hiệp hai — đấu đạo niệm, hiệp ba — đấu một thức thần thông. Ba hiệp phân thắng thua.","nguon":["@c1401"]},{"id":"than-thong-huong-hoa","name":"Thần thông hương hỏa","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Độc hữu bước thứ ba","hePhai":"","soHuu":["Lỗ Phu Tử"],"blurb":"Thần thông chỉ tu sĩ bước thứ ba có hương hỏa mới thi triển được, là lý do bước thứ ba trở thành tồn tại cực mạnh.","detail":"Lỗ Phu Tử giải thích chỉ có hương hỏa mới có thể thi triển thần thông hương hỏa. Tu sĩ chưa đạt bước thứ ba không có hương hỏa nên không thể dùng.","thuocTinh":"Hương hỏa","nguonGoc":"","yeuCau":"Phải đạt bước thứ ba, sở hữu hương hỏa","congNang":["Thần thông độc hữu của tu sĩ bước thứ ba, cần hương hỏa làm nguồn lực thi triển"],"tabs":{"tienTrinh":[{"chuong":"@c1403","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Lỗ Phu Tử giải thích cơ chế","text":"Lỗ Phu Tử tuyên bố chỉ hương hỏa mới thi triển được thần thông hương hỏa, Vương Lâm chưa đạt bước thứ ba nên không có hương hỏa.","anchor":"Chỉ có hương hỏa mới có thể thi triển ra thần thông hương hỏa"}]},"capNhatToi":"@c1403","nguon":["@c1403"]},{"id":"phong-tien-gioi","name":"Phong Tiên Giới","cn":"封仙界","loai":"bi-thuat","loaiLabel":"Bí thuật / Trận pháp phụ","phamCap":"Không rõ","hePhai":"Hướng gia (La Thiên Tinh Vực)","soHuu":["Lão tổ Hướng gia"],"blurb":"Biến ảo do lão tổ Hướng gia thi triển trong tinh trận, phóng vô tận hư ảnh tiên nhân hình thành khí thế ngân hà bức tới đối thủ.","detail":"Phong Tiên Giới là biến ảo được triển khai bên trong tinh trận La Thiên Tinh Vực, do lão tổ Hướng gia (tổ tiên Hướng gia) thi triển. Khi kích hoạt, vô tận hư ảnh của tiên nhân đồng loạt lao ra, hình thành khí thế mạnh mẽ như ngân hà. Tuy nhiên, khi đối mặt uy áp đồng thời của hai tu sĩ bước thứ ba (Linh Động Thượng Nhân và Chu Cẩn), Phong Tiên Giới bị quét sạch hoàn toàn, chia năm xẻ bảy rồi nhanh chóng tiêu tan.","nguon":["@c1404"]},{"id":"than-thong-ba-mang","name":"Thần thông ba mạng","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chưa rõ","hePhai":"","soHuu":[],"blurb":"Thần thông ba mạng là một loại thần thông bí ẩn liên quan tới Diêu gia, được Cổ Yêu lục tinh tiết lộ khi bị Vương Lâm bắt sống tại @c1406. Công năng cụ thể chưa được làm rõ trong tiến trình hiện có.","detail":"Khi bị Vương Lâm bắt sống, Cổ Yêu lục tinh đã dùng một bí mật kinh thiên để cầu xin tha mạng: tại Diêu gia có thể đạt được một loại thần thông gọi là thần thông ba mạng. Thông tin này khiến Vương Lâm đôi mắt lóe sáng, cho thấy đây là điều có giá trị rất lớn. Tuy nhiên, tính tới mốc hiện có, tác dụng cụ thể, cách tu luyện và bản chất của thần thông này chưa được tiết lộ.","congNang":["Chưa rõ, chỉ được nhắc tên là thần thông có thể đạt được tại Diêu gia"],"tabs":{"tienTrinh":[{"chuong":"@c1406","loai":"nhắc tới","importance":"major","giaiDoan":"Lần đầu được nhắc tên","text":"Cổ Yêu lục tinh bị Vương Lâm bắt sống, cầu xin tha mạng bằng cách tiết lộ bí mật kinh thiên liên quan Diêu gia: nơi đó có thể đạt được thần thông ba mạng.","anchor":"Ngươi có thể đi tới đó, đạt được một loại thần thông, thần thông ba mạng"}]},"nguon":["@c1406"]},{"id":"thon-phe-u-minh-thu","name":"Thôn phệ","cn":"吞噬","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thượng cổ thần thông","hePhai":"U Minh Thú","soHuu":["U Minh Thú"],"blurb":"Thần thông thứ hai của U Minh Thú — mở miệng nuốt vạn vật vào thế giới nội tại, nơi thời gian lưu chuyển vạn đến trăm ngàn vạn năm khiến mục tiêu hóa cát bụi.","detail":"U Minh Thú mở miệng từ tám ngàn trượng tới hơn mười vạn trượng, hồn phách hiện ra — hư ảnh một con U Minh Thú chỉ có cái miệng kích cỡ bằng cả tinh vực. Bên trong cơ thể có một thế giới thần thông lúc lớn lúc nhỏ, thời gian lưu chuyển vạn năm thậm chí trăm ngàn vạn năm; bất kỳ vật gì bị nuốt — pháp bảo, mãnh thú, tu sĩ, tu chân tinh, cả vùng tinh không — đều bị nhốt và theo thời gian hóa cát bụi. Thời thái cổ, U Minh Thú từng nuốt cả vùng tinh không. Ngàn năm không há miệng, mỗi lần há miệng là gánh nặng rất lớn với bản thân con thú. Khi thi triển, hồn phách xuất hiện bên ngoài. Lực hút khủng khiếp nuốt sương mù, hàng chục tu chân tinh hoang dã, hút cả Linh Động, Chu Cẩn, Vọng Nguyệt và Cổ Tức Diệp vào thế giới bên trong. Ngay cả Lỗ Phu Tử và Vọng Nguyệt cũng không dám trêu chọc U Minh Thú.","nguon":["@c1410"]},{"id":"tang-hinh-u-minh-thu","name":"Tàng hình","cn":null,"loai":"than-thong","loaiLabel":"Thần thông","phamCap":null,"hePhai":"U Minh Thú","soHuu":["U Minh Thú"],"blurb":"Thần thông thứ nhất của U Minh Thú — thân thể khổng lồ hóa vô hình, người đứng cạnh cũng khó phát hiện.","detail":"U Minh Thú có thể khiến thân thể khổng lồ hóa thành hư vô, giống như vô hình, khiến cho người ta khó có thể tìm được. Khi bị kinh động, phản ứng mặc định của con thú nhát gan này là tàng hình bỏ chạy thay vì chiến đấu.","nguon":["@c1410"]},{"id":"phong-an-bon-menh-thu-ba-buoc","name":"Phong ấn bổn mệnh thú ba bước","cn":null,"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":null,"hePhai":"Đạo Cổ / Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Phong ấn bổn mệnh thú ba bước là quy trình ba tầng phong ấn dùng để thu phục mãnh thú thành Cổ Thần bổn mệnh thú. Tại mốc hiện tại, Vương Lâm đã hoàn thành bước một và bước hai nhưng phong ấn bị phá hủy một phần, bước ba chưa được tiết lộ và quy trình chưa hoàn tất.","detail":"Quy trình gồm ba bước. Bước một (phong ấn bên ngoài thân thể): đánh một chưởng chứa khí tức Đạo cổ lên thân mãnh thú, hóa thành ấn ký ẩn chứa khí tức Đạo cổ. Bước hai (phong hồn — phong ấn bên trong): đợi hồn phách mãnh thú xuất hiện, dùng bảy tinh điểm Cổ Thần lần lượt khắc phong ấn lên hồn khẩu, thắp sáng từng tinh điểm một. Vương Lâm thi triển sau khi dùng 100 roi Côn Cực Tiên bức mãnh thú, hoàn thành cả bảy tinh điểm Cổ Thần, song ánh sáng thất thải bùng lên phá hủy hơn nửa phong ấn ngoài và dập tắt ba tinh điểm hồn ấn, khiến quy trình thất bại một phần. Bước ba chưa được tiết lộ trong tiến trình hiện có.","nguon":["@c1410","@c1412"],"tabs":{"tienTrinh":[{"chuong":"@c1412","loai":"thi triển","importance":"major","giaiDoan":"Vương Lâm hoàn thành cả ba bước phong ấn, thu phục U Minh Thú","text":"Vương Lâm lần lượt hoàn thành phong ấn ngoài, hồn phong bằng bảy tinh điểm Cổ Thần sau 100 roi Côn Cực Tiên, và phong ấn máu thịt bằng cấm chế Cổ Thần lực. Tuyên phong U Minh Thú làm bổn mệnh thú.","anchor":"Trong ba bước phong ấn, vẫn còn một bước cuối cùng, đó là phong ấn máu thịt bên trong"}]},"aliases":["Phong ấn bổn mệnh thú ba bước (phương pháp Vương Lâm)"],"congNang":["Thu phục mãnh thú thành Cổ Thần bổn mệnh thú thông qua ba tầng phong ấn @c1412","Bước một: đánh chưởng khí tức Đạo cổ lên thân mãnh thú, tạo ấn ký phong ấn bên ngoài @c1412","Bước hai: dùng bảy tinh điểm Cổ Thần khắc phong ấn lên hồn khẩu của mãnh thú, phong ấn hồn phách @c1412"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1412","tangDatToi":"Hoàn thành cả ba bước","trangThai":"thanh-cong"}],"dacDiem":"Quy trình đòi hỏi khí tức Đạo cổ và bảy tinh điểm Cổ Thần; phong ấn chia thành tầng ngoài (thân thể) và tầng trong (hồn phách), dễ bị ánh sáng thất thải phản phệ phá hủy một phần khi thi triển."},{"id":"chu-tuoc-hu-anh","name":"Chu Tước hư ảnh","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Bổn nguyên","soHuu":["Vương Lâm"],"blurb":"Hư ảnh Chu Tước hiện ra phía sau Vương Lâm, dung hợp với ngọn lửa chín màu tạo biển lửa lôi đình bao phủ tinh không.","detail":"Hư ảnh Chu Tước hiện ra phía sau Vương Lâm, phát tiếng kêu Chu Tước, dung hợp với lửa chín màu từ mắt trái lao vào tinh không, biến tám ngàn vạn trượng tinh không thành biển lửa lôi đình. Biểu hiện cho việc thi triển toàn bộ hóa bổn nguyên.","thuocTinh":"Hỏa / Lôi","congNang":["Dung hợp với ngọn lửa chín màu tạo biển lửa lôi đình luyện hóa tinh không"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1411","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1411","loai":"thi triển","importance":"normal","giaiDoan":"Dung hợp lửa chín màu luyện hóa tinh không","text":"Hư ảnh Chu Tước hiện ra phía sau Vương Lâm, dung hợp lửa chín màu biến tinh không tám ngàn vạn trượng thành biển lửa lôi đình.","anchor":"ở phía sau Vương Lâm, hư ảnh Chu Tước hiện ra, phát ra một tiếng kêu Chu Tước"}]},"nguon":["@c1411"]},{"id":"chin-giot-doc-dich","name":"Chín giọt độc dịch","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Chín giọt độc dịch chứa trong Thiên Hoàng Lô, phóng ra tạo sương độc phá tàng hình.","detail":"Được Vương Lâm phóng ra từ Thiên Hoàng Lô, dung nhập vào lôi hóa tạo sương độc màu đen bao phủ tinh không, bức U Minh Thú mất tàng hình hiện nguyên hình. Vật phẩm quý giá, dùng xong thu hồi, không tiêu hao vĩnh viễn.","congNang":["Dung nhập lôi hóa tạo sương độc phá tàng hình"],"tabs":{"tienTrinh":[{"chuong":"@c1411","loai":"thi triển","importance":"normal","giaiDoan":"Bức U Minh Thú hiện hình","text":"Vương Lâm phóng chín giọt độc dịch từ Thiên Hoàng Lô dung nhập lôi hóa tạo sương độc, bức U Minh Thú mất tàng hình.","anchor":"chín giọt độc dịch bên trong Thiên Hoàng Lô nhanh chóng lao ra, dung nhập vào bên trong lôi hóa"}]},"nguon":["@c1411"]},{"id":"cuu-diet-le-thien-tran","name":"Cửu Diệt Lê Thiên Trận","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Thần Tông","soHuu":["Thủy Đạo Tử"],"blurb":"Trận pháp được Thủy Đạo Tử ra lệnh bố trí bên ngoài Thần Tông để phòng thủ trước Vương Lâm.","detail":"Thủy Đạo Tử ra lệnh triệu tập tu sĩ Vân Hải tinh vực bố trí trận này bên ngoài Thần Tông, chuẩn bị cho cuộc đối đầu với Vương Lâm trở về.","congNang":["Phòng thủ cấp tông môn, bố trí bên ngoài Thần Tông"],"tabs":{"tienTrinh":[{"chuong":"@c1414","loai":"xuất hiện","importance":"normal","giaiDoan":"Lệnh bố trận","text":"Thủy Đạo Tử ra lệnh triệu tập tu sĩ Vân Hải tinh vực bố trí Cửu Diệt Lê Thiên Trận bên ngoài Thần Tông.","anchor":"bố trí Cửu Diệt Lê Thiên Trận bên ngoài Thần Tông chúng ta"}]},"nguon":["@c1414"]},{"id":"sat-luc-bon-nguyen","name":"Sát lục bổn nguyên","cn":"杀戮本源","loai":"khac","loaiLabel":"Bổn nguyên","phamCap":"Cực hiếm","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Sát lục bổn nguyên là loại bổn nguyên cực kỳ hiếm, sinh ra từ sát niệm tích lũy cả đời giết chóc của Vương Lâm, manh nha trên đường tiến về Thần Tông. Sát khí từ sương mù đóng băng và cơ thể Vương Lâm dung hợp, hình thành nên khí tức bổn nguyên mới mẻ này. (+) Bổn nguyên sát lục của Vương Lâm, trong chương này được dùng làm sát khí biến đổi thiên tượng của sát trận. [CAN-SOAT-GOP]","detail":"Vạn vật trong thiên địa đều có thể trở thành bổn nguyên, nhưng sát lục bổn nguyên là loại cực kỳ khó thành — không phải giết nhiều thì có thể đạt được, cơ chế hình thành của nó không ai hiểu rõ. Trên đường Vương Lâm tiến về Thần Tông, sát niệm tích lũy cả đời bỗng phát sinh biến hóa quỷ dị, manh nha một tia khí tức bổn nguyên hoàn toàn mới (@c1415). Sau đó, sát khí từ sương mù đóng băng và cơ thể Vương Lâm dung hợp với nhau, chính thức hình thành sát lục bổn nguyên, uy áp tỏa ra khiến toàn bộ tu sĩ xung quanh đều cảm nhận được (@c1416). Đây là loại bổn nguyên sinh từ sát niệm thuần túy, nguồn gốc hoàn toàn gắn liền với con đường tu luyện đẫm máu của Vương Lâm.","thuocTinh":"Sát","nguonGoc":"Sinh từ sát niệm cả đời giết chóc của Vương Lâm","dacDiem":"Cực kỳ hiếm, vạn vật đều có thể thành bổn nguyên nhưng sát lục bổn nguyên rất khó thành; không phải giết nhiều thì có thể đạt được, cơ chế hình thành không ai hiểu rõ; sinh ra từ sự dung hợp giữa sát khí sương mù đóng băng và thân thể tu luyện.","trangThai":"Manh nha","capNhatToi":"@c1415","congNang":["Sát niệm tích lũy cả đời phát sinh biến hóa quỷ dị, manh nha khí tức bổn nguyên mới (@c1415)","Sát khí từ sương mù đóng băng và cơ thể Vương Lâm dung hợp, hình thành sát lục bổn nguyên, uy áp lan tỏa ảnh hưởng toàn bộ tu sĩ xung quanh (@c1416)"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1415","tangDatToi":"Mới lộ","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1415","loai":"xuat-hien","importance":"major","giaiDoan":"Manh nha","text":"Trên đường tiến về Thần Tông, sát niệm Vương Lâm phát sinh biến hóa quỷ dị, manh nha sát lục bổn nguyên — loại bổn nguyên cực kỳ hiếm.","anchor":"Sát lục bổn nguyên! Vạn vật trong thiên địa đều có thể trở thành bổn nguyên"},{"chuong":"@c1416","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu lộ diện","text":"Sát khí từ sương mù đóng băng và cơ thể Vương Lâm dung hợp hình thành sát lục bổn nguyên, khiến toàn bộ tu sĩ bước thứ ba chấn động. Chủ nhân phong giới năm xưa cũng không thể nghiên cứu ra loại bổn nguyên này.","anchor":"đây chính là bổn nguyên mà chủ nhân phong giới năm xưa cũng không thể nghiên cứu ra"}]},"nguon":["@c1415","@c1416","@c1769"]},{"id":"am-duong-mon-do","name":"Âm Dương Môn Đồ","cn":"阴阳门徒","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Thủy Đạo Tử"],"blurb":"Chiêu thức quyết tử của Thủy Đạo Tử, triệu hồi vô số Âm Dương Môn Đồ từ khe nứt phía sau hóa thành trường thương khổng lồ, dung hợp toàn bộ tu vi và hương hỏa cả đời tạo một đòn đâm uy lực cực đại nhắm vào Vương Lâm.","detail":"Trong trận chiến với Vương Lâm, Thủy Đạo Tử mở khe nứt lớn phía sau, vô số Âm Dương Môn Đồ bay ra rồi hợp nhất hóa thành một cây trường thương khổng lồ. Cây thương này dung hợp toàn bộ tu vi cùng hương hỏa tích lũy cả đời của Thủy Đạo Tử, tạo thành đòn quyết tử đâm thẳng vào Vương Lâm. Uy lực của chiêu thức kinh thiên động địa, khiến tu chân tinh nứt vỡ, dường như sắp hủy diệt. Đây là chiêu liều mạng, đánh đổi toàn bộ tích lũy bản thân để tung ra một kích duy nhất.","congNang":["Triệu hồi vô số Âm Dương Môn Đồ từ khe nứt, hợp nhất hóa thành trường thương khổng lồ @c1417","Dung hợp toàn bộ tu vi và hương hỏa cả đời của người thi triển tạo đòn quyết tử uy lực cực đại @c1417"],"nguoiTu":[{"ten":"Thủy Đạo Tử","tuChuong":"@c1417","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1417","loai":"thi-triển","importance":"major","giaiDoan":"Thủy Đạo Tử liều mạng tung chiêu cuối","text":"Thủy Đạo Tử triệu hồi vô số Âm Dương Môn Đồ hóa trường thương dung hợp tu vi và hương hỏa cả đời đâm Vương Lâm. Uy lực khiến tu chân tinh nứt vỡ sắp hủy diệt.","anchor":"Cây thương này dung hợp tu vi cả đời của Thủy Đạo Tử, dung hợp toàn bộ hương hỏa của hắn"}]},"nguon":["@c1417"],"uyLuc":"Uy lực kinh thiên, khiến tu chân tinh nứt vỡ, dường như sắp hủy diệt.","dacDiem":"Chiêu thức mang tính quyết tử, đánh đổi toàn bộ tu vi và hương hỏa cả đời để hóa thành một kích duy nhất, không thể lặp lại."},{"id":"am-duong-tien-long","name":"Âm Dương Tiên Long","cn":"阴阳仙龙","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Bổn nguyên lực","soHuu":["Thủy Đạo Tử"],"blurb":"Thần thông thuộc hệ Bổn nguyên lực của Thủy Đạo Tử: hai đạo bổn nguyên lực một trắng một đen hóa hai con cự long cuộn nhau, kèm tấm lưới đen trắng có khí tức hủy diệt.","detail":"Thủy Đạo Tử thi triển khi đối đầu quyền thứ hai của Vương Lâm. Hai con cự long một trắng một đen cuộn quấn lẫn nhau cùng tấm lưới bổn nguyên lực đen trắng mang khí tức hủy diệt. Tất cả bị nắm tay hư ảo có đầu Đạo cổ dung nhập của Vương Lâm phá tan hoàn toàn.","congNang":["Hai cự long đen trắng cuộn quấn tấn công kết hợp tấm lưới bổn nguyên lực đen trắng mang khí tức hủy diệt phòng thủ"],"nguoiTu":[{"ten":"Thủy Đạo Tử","tuChuong":"@c1418","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1418","loai":"thi triển","importance":"normal","giaiDoan":"Thủy Đạo Tử dùng chống Vương Lâm","text":"Thủy Đạo Tử thi triển Bổn nguyên lực Âm Dương Tiên Long chống quyền thứ hai của Vương Lâm, hai cự long đen trắng cùng tấm lưới bổn nguyên lực bị phá tan hoàn toàn.","anchor":"Bổn nguyên lực, âm dương tiên long!"}]},"nguon":["@c1418"]},{"id":"dao-co-hoa-menh-thuat","name":"Đạo Cổ Hóa Mệnh Thuật","cn":"道古化命术","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cực hiếm (cả đời chỉ thi triển 3 lần)","hePhai":"Cổ tộc","soHuu":["Vương Lâm"],"blurb":"Đạo Cổ Hóa Mệnh Thuật là thuật pháp truyền thừa từ vùng đất cổ mộ của cổ tộc tổ tiên, có khả năng chuyển toàn bộ sinh cơ của người đã chết sang người có liên kết mệnh hồn với họ, đồng thời hóa giải liên kết mệnh hồn đó. Thuật pháp bị giới hạn nghiêm ngặt: cả đời người tu luyện chỉ được thi triển tối đa ba lần.","detail":"Đạo Cổ Hóa Mệnh Thuật bắt nguồn từ truyền thừa vùng đất cổ mộ, thuộc về cổ tộc tổ tiên. Thuật pháp này tác động dựa trên mối liên kết mệnh hồn giữa hai người: khi một bên đã chết, toàn bộ sinh cơ của người chết sẽ được chuyển sang người còn lại đang mang liên kết mệnh hồn, đồng thời phá giải luôn sợi dây liên kết ấy. Vương Lâm đã thi triển lần đầu tiên bằng cách đọc khẩu quyết, chuyển toàn bộ sinh cơ của Thủy Đạo Tử sang Mộc Băng Mi, hóa giải liên kết mệnh hồn mà Thủy Đạo Tử đã lén đặt lên nàng. Tuy nhiên, thuật pháp này tỏ ra vô dụng đối với Lý Mộ Uyển, ám chỉ tình trạng của nàng có bản chất khác biệt so với liên kết mệnh hồn thông thường.","thuocTinh":"Chuyển sinh cơ, hóa giải mệnh hồn liên kết","nguonGoc":"Truyền thừa vùng đất cổ mộ, cổ tộc tổ tiên","dacDiem":"Cả đời người thi triển chỉ được sử dụng tối đa ba lần; cần đọc khẩu quyết để kích hoạt; chỉ có hiệu quả khi tồn tại liên kết mệnh hồn giữa hai đối tượng.","congNang":["Chuyển toàn bộ sinh cơ của người đã chết sang người có liên kết mệnh hồn với họ @c1421","Hóa giải liên kết mệnh hồn giữa hai người @c1421"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1421","tangDatToi":"Lần thi triển thứ 1","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1421","loai":"thi triển","importance":"major","giaiDoan":"Lần thi triển đầu tiên","text":"Vương Lâm đọc khẩu quyết Đạo Cổ Hóa Mệnh Thuật chuyển toàn bộ sinh cơ Thủy Đạo Tử sang Mộc Băng Mi, hóa giải liên kết mệnh hồn và cứu nàng. Cửu tinh cổ Yêu Quỷ Tông nhận ra ngay và biến sắc.","anchor":"Đạo Cổ hóa mệnh thuật! Đây là Đạo cổ hóa mệnh thuật!"}]},"nguon":["@c1421"]},{"id":"pha-hon-nhat-kiem","name":"Phá hồn nhất kiếm","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm quyết","phamCap":"Không rõ","hePhai":"Thị Kiếm tộc","soHuu":["Thị Kiếm tộc"],"blurb":"Công pháp do Thị Kiếm tộc tu hành, uy lực kinh người, là đặc trưng chiến đấu của tu sĩ hộ điện Thiên Phạt Điện.","detail":"Mấy ngàn tu sĩ hắc y Thị Kiếm tộc đều tu hành Phá hồn nhất kiếm, mi tâm có ấn ký thanh kiếm màu đen, khí tức lạnh băng, sát khí lặng.","congNang":["Phá hồn bằng kiếm, uy lực kinh người"],"nguoiTu":[{"ten":"Thị Kiếm tộc","tuChuong":"@c1423","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1423","loai":"xuất hiện","importance":"normal","giaiDoan":"Xuất hiện cùng Thị Kiếm tộc","text":"Mấy ngàn tu sĩ hắc y Thị Kiếm tộc tu hành Phá hồn nhất kiếm xuất hiện bên ngoài Phong Giới Đại Trận cùng Thiên Phạt Điện.","anchor":"tu hành Phá hồn nhất kiếm, uy lực kinh người"}]},"nguon":["@c1423"]},{"id":"doc-cong-nam-chieu","name":"Độc công của Nam Chiếu Thượng Nhân","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Nam Chiếu Thượng Nhân"],"blurb":"Độc công cùng tề danh với Đại Hoang Thượng Nhân. Tay phải hóa đen chứa kịch độc, có thể giết chết cường giả.","detail":"Nam Chiếu Thượng Nhân sở hữu độc công cùng tề danh với Đại Hoang Thượng Nhân. Khi thi triển, tay phải hóa đen chứa kịch độc, xuyên qua phòng ngự tấn công trực tiếp đối thủ. Uy lực đủ để buộc Vương Lâm phải lui, một mình đủ sức giết hắn.","congNang":["Tay phải hóa đen chứa kịch độc tấn công tiếp xúc trực tiếp"],"nguoiTu":[{"ten":"Nam Chiếu Thượng Nhân","tuChuong":"@c1425","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1425","loai":"thi triển","importance":"normal","giaiDoan":"Thi triển trong đại chiến giới nội","text":"Nam Chiếu Thượng Nhân dùng độc công tay phải hóa đen xuyên qua hỏa điểu vỗ thẳng Vương Lâm, buộc hắn phải lui.","anchor":"trên người hắn còn có độc công cùng tề danh với Đại Hoang Thượng Nhân"}]},"nguon":["@c1425"]},{"id":"huong-hoa-gioi-khong-linh","name":"Hương hỏa giới Không Linh","cn":"香火界空灵","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không Linh cấp","hePhai":"Không Linh tu sĩ","soHuu":["Nam Chiếu Thượng Nhân"],"blurb":"Hương hỏa giới Không Linh là trạng thái cảnh giới mà hương hỏa giới dung hợp hoàn toàn vào tu sĩ khi đạt Không Linh, biến tu sĩ thành một thiên địa riêng biệt. Hồn phách thăng hoa, nguyên thần biến thành linh thần, niết lực chuyển hóa thành linh lực vượt xa tầng Không Niết.","detail":"Khi tu sĩ đạt cảnh giới Không Linh, hương hỏa giới không còn tồn tại tách biệt mà dung hợp hoàn toàn vào bản thân tu sĩ, khiến mỗi Không Linh tu sĩ tương đương một thiên địa độc lập. Hồn phách tu sĩ thăng hoa, nguyên thần biến thành linh thần, và niết lực — tức hương hỏa lực ở tầng Không Niết — chuyển hóa thành linh lực riêng biệt, uy lực vượt xa Không Niết. Trong chiến đấu, tu sĩ Không Linh có thể hút đối thủ vào hương hỏa giới của mình, sử dụng ý chí của hàng trăm triệu dân hương hỏa để mê hoặc đối phương, đồng thời hóa toàn bộ không trung trong hương hỏa giới thành bàn tay khổng lồ để tấn công. Diệu Âm là trường hợp ngoại lệ vì nguyên nhân đặc biệt không chọn dung hợp hương hỏa giới, nên từng bị đoạt mất hương hỏa.","congNang":["Hút đối thủ vào hương hỏa giới riêng của tu sĩ @c1426","Dùng ý chí hàng trăm triệu dân hương hỏa mê hoặc đối thủ @c1426","Hóa toàn bộ không trung trong hương hỏa giới thành bàn tay khổng lồ để tấn công @c1426","Niết lực chuyển hóa thành linh lực riêng biệt, uy lực vượt xa Không Niết @c1426"],"tabs":{"tienTrinh":[{"chuong":"@c1426","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Hé lộ toàn bộ hệ thống Không Linh","text":"Chương giải thích chi tiết: Không Niết dùng niết lực tức hương hỏa lực, còn Không Linh thì hồn phách thăng hoa, nguyên thần biến thành linh thần, hương hỏa giới dung hợp vào tu sĩ trở thành thiên địa riêng, niết lực chuyển hóa thành linh lực. Nam Chiếu Thượng Nhân thi triển hút Vương Lâm vào hương hỏa giới tấn công.","anchor":"mỗi một Không Linh tu sĩ có thể so sánh với một thiên địa"}]},"capNhatToi":"@c1426","nguon":["@c1426"],"uyLuc":"Một đòn Không Linh vượt xa tầng Không Niết, linh lực chuyển hóa từ niết lực mang uy lực vượt trội hoàn toàn.","dacDiem":"Hương hỏa giới dung hợp vào tu sĩ khiến mỗi Không Linh tu sĩ tương đương một thiên địa riêng; hồn phách thăng hoa, nguyên thần biến thành linh thần."},{"id":"huyet-sam","name":"Huyết Sam","loai":"than-thong","loaiLabel":"Thần thông","hePhai":"Sát đạo","soHuu":["Hồng Sam Tử"],"blurb":"Huyết Sam là thần thông bản mệnh của Hồng Sam Tử (Huyết Sam đồng tử), bức toàn bộ máu huyết bên trong cơ thể nạn nhân ra ngoài da tạo thành trường sam đỏ bao phủ thân thể, biến họ thành xác sống bị khống chế điên cuồng chém giết đồng đội. Hiệu lực phạm vi cực rộng, trùm lên hàng ngàn tu sĩ cùng lúc kể cả tu sĩ bước thứ ba, gắn liền với truyền thuyết Huyết Sam đồng tử lưu truyền mấy vạn năm ở giới ngoại.","detail":"Huyết Sam là thần thông bản mệnh của Hồng Sam Tử, nhân vật gắn với truyền thuyết Huyết Sam đồng tử đã lưu truyền mấy vạn năm ở giới ngoại kể từ lần hai giới đại chiến trước. Khi thi triển, thần thông phóng hồng quang từ bên trong cơ thể tu sĩ mục tiêu, bức toàn bộ máu huyết xuyên qua da tạo thành trường sam đỏ bao phủ toàn thân. Nạn nhân lập tức biến thành thây khô, nguyên thần bị giam giữ bên trong xác, tử khí tràn ngập khiến họ trở thành xác sống mặc huyết sam, hoàn toàn bị khống chế và điên cuồng chém giết đồng đội để cướp máu tươi. Tại chương @c1427, Hồng Sam Tử lần đầu thi triển Huyết Sam trên chiến trường, bức máu huyết của hàng ngàn tu sĩ giới ngoại cùng lúc, cho thấy phạm vi ảnh hưởng khổng lồ và hiệu lực không phân biệt cảnh giới, trùm lên cả tu sĩ bước thứ ba.","congNang":["Phóng hồng quang từ bên trong cơ thể nạn nhân, bức toàn bộ máu huyết ra ngoài da tạo thành trường sam đỏ bao phủ thân thể @c1427","Biến nạn nhân thành thây khô, nguyên thần bị giam trong xác, tử khí tràn vào khiến trở thành xác sống mặc huyết sam bị khống chế @c1427","Xác sống bị khống chế điên cuồng chém giết đồng đội để cướp máu tươi @c1427","Hiệu lực phạm vi rộng, trùm lên hàng ngàn tu sĩ cùng lúc kể cả tu sĩ bước thứ ba @c1427"],"nguoiTu":[{"ten":"Hồng Sam Tử","tuChuong":"@c1427","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1427","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển trong đại chiến hai giới","text":"Hồng Sam Tử thi triển Huyết Sam lần đầu tiên, bức máu huyết hàng ngàn tu sĩ giới ngoại thành trường sam đỏ biến họ thành xác sống. Hiệu lực trùm lên cả Nam Chiếu Thượng Nhân bước thứ ba.","anchor":"Trường sam do máu tươi tạo thành xuất hiện trong nháy mắt liền lập tức co rút lại"}]},"nguon":["@c1427"],"uyLuc":"Một lần thi triển bức máu huyết hàng ngàn tu sĩ giới ngoại cùng lúc biến thành xác sống, kể cả tu sĩ bước thứ ba cũng không thoát khỏi hiệu lực.","dacDiem":"Thần thông bản mệnh dạng trường phạm vi, tấn công từ bên trong cơ thể nạn nhân ra ngoài, không cần tiếp xúc trực tiếp; máu huyết bị bức ra hóa thành trường sam đỏ đặc trưng, nạn nhân mất hoàn toàn tự chủ và quay sang tàn sát đồng đội."},{"id":"phong-an-phong-diet-toc","name":"Phong ấn Phong Diệt Tộc","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông bộ tộc","phamCap":"Không rõ","hePhai":"Phong Diệt Tộc","soHuu":["Phong Diệt Tộc"],"blurb":"Phong ấn Phong Diệt Tộc là thần thông bộ tộc của Phong Diệt Tộc — Thái Cổ Kỳ Tộc, đòi hỏi người thi triển hiến tế sinh mạng để đánh ra phong ấn bất khả cự. Tại trận chiến với giới ngoại, ba tử sĩ Phong Diệt Tộc ẩn trong đại quân hiện thân hiến mạng, đánh ba đạo phong ấn phong tỏa nguyên lực, thể lực và sinh cơ của mục tiêu, khiến đối phương hoàn toàn mất sức chiến đấu.","detail":"Phong ấn Phong Diệt Tộc là bí thuật truyền thừa của Phong Diệt Tộc, một trong các Thái Cổ Kỳ Tộc. Mỗi đạo phong ấn yêu cầu một người hiến tế sinh mạng để thi triển, đổi mạng lấy phong ấn tuyệt đối. Ba tử sĩ Phong Diệt Tộc ẩn thân trong đại quân giới ngoại, đợi thời cơ hiện thân đánh ra ba đạo phong ấn liên tiếp. Phong ấn thứ nhất phong tỏa nguyên lực toàn thân mục tiêu. Phong ấn thứ hai phong tỏa thể lực, khiến mục tiêu lão hóa nhanh chóng biến thành lão già. Phong ấn thứ ba phong tỏa sinh cơ, từ mi tâm rút lấy sức mạnh đặc thù của mục tiêu — chẳng hạn sức mạnh Cổ Thần. Phong ấn từ mi tâm lan ra hình thành lưới u quang phủ toàn thân, không thể chống cự khi giáng xuống. Đặc tính cốt lõi của phong ấn này là cho dù người thi triển đã chết, phong ấn vẫn không tan, bảo đảm hiệu quả vĩnh cửu trừ","thuocTinh":"Phong ấn","nguonGoc":"Phong Diệt Tộc — Thái Cổ Kỳ Tộc","yeuCau":"Hiến tế sinh mạng người thi triển","uyLuc":"Ba đạo phong ấn liên tiếp tước đoạt toàn bộ nguyên lực, thể lực và sinh cơ của mục tiêu, khiến đối phương lão hóa thành lão già và bị rút sạch sức mạnh đặc thù, hoàn toàn mất khả năng chiến đấu; phong ấn bất khả cự và không tan ngay cả khi người thi triển đã chết.","dacDiem":"Mỗi đạo phong ấn đòi hỏi một người hiến tế sinh mạng để thi triển, lấy cái chết đổi phong ấn tuyệt đối; phong ấn không tiêu tan theo cái chết của người thí pháp, và khi giáng xuống sẽ hình thành lưới u quang từ mi tâm phủ toàn thân, không thể chống cự.","trangThai":"Đã bị Vương Lâm phá vỡ bằng ngoại lực","congNang":["Phong ấn nguyên lực toàn thân mục tiêu, khiến đối phương không thể vận chuyển nguyên lực @c1428","Phong ấn thể lực, khiến mục tiêu lão hóa nhanh chóng thành lão già @c1428","Phong ấn sinh cơ, từ mi tâm rút sức mạnh đặc thù của mục tiêu (như sức mạnh Cổ Thần) @c1428","Hình thành lưới u quang từ mi tâm lan ra phủ toàn thân, bất khả cự khi giáng xuống @c1428","Phong ấn không tan dù người thi triển đã chết, duy trì hiệu quả vĩnh viễn trừ khi bị ngoại lực phá giải @c1428"],"nguoiTu":[{"ten":"Ba tử sĩ Phong Diệt Tộc","tuChuong":"@c1428","tangDatToi":"","trangThai":"tu-vong"}],"tabs":{"tienTrinh":[{"chuong":"@c1428","loai":"thi triển","importance":"major","giaiDoan":"Ba tử sĩ hiến mạng phong ấn Vương Lâm","text":"Ba tử sĩ Phong Diệt Tộc ẩn trong đại quân giới ngoại, hiện thân hiến tế sinh mạng đánh ba đạo phong ấn lên Vương Lâm. Phong ấn thành công nhưng cả ba bị giết. Vương Lâm sau đó mượn ngoại lực tấn công của mấy vạn tu sĩ phá vỡ cả ba đạo.","anchor":"gọi ra thần thông của bộ tộc, phong ấn nguyên lực toàn thân của người này"}]},"capNhatToi":"@c1428","dinhDanh":"goc","nguon":["@c1428"]},{"id":"tran-phap-cai-tien-van-hai","name":"Trận pháp cải tiến Vân Hải","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Vân Hải","soHuu":["Hồng Sam Tử"],"blurb":"Trận pháp do Hồng Sam Tử truyền cho gần ba vạn tu sĩ Vân Hải trước trận chiến, nhưng liên tục bị Vân Lạc Đại Ti chỉ huy phá hoại, không thể bày thành công.","detail":"Trận pháp giết địch do Hồng Sam Tử cải tiến và truyền dạy, cần gần ba vạn tu sĩ Vân Hải phối hợp bày trận. Trong đại chiến Vân Hải, tu sĩ nhiều lần cố bày trận nhưng mỗi lần sắp thành hình đều bị phá do Vân Lạc Đại Ti điều khiển đại quân giới ngoại linh hoạt tiên đoán mọi bước đi, cho tu sĩ lao tới phá hoại.","nguon":["@c1429"],"tabs":{"tienTrinh":[{"chuong":"@c1429","loai":"thi triển","importance":"normal","giaiDoan":"Nhiều lần bày trận thất bại","text":"Gần ba vạn tu sĩ Vân Hải cố bày trận pháp cải tiến nhưng liên tục thất bại do Vân Lạc Đại Ti chỉ huy phá hoại.","anchor":"Trận pháp cải tiến của Vân Hải này thủy chung vẫn không thể bày ra được"}]}},{"id":"tam-dau-quy-anh","name":"Tam đầu quỷ ảnh","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Nữ tử áo đỏ"],"blurb":"Tam đầu quỷ ảnh là thần thông của Tiên Phi, được hóa thành từ ba giọt máu bổn mệnh, có thể ẩn thân trong cuồng phong hàn băng rồi bất ngờ hiện nguyên hình tấn công. Đòn đánh trúng tạo vết máu hình đầu quỷ khuếch tán trên cơ thể đối phương, gây sát thương chí mạng.","detail":"Tiên Phi — nữ tử áo đỏ — thi triển thần thông này bằng cách dùng ba giọt máu bổn mệnh hóa thành tam đầu quỷ ảnh. Quỷ ảnh có thể ẩn mình trong cuồng phong hàn băng, biến thành bóng đỏ rồi hiện nguyên hình bất ngờ tấn công đối thủ. Khi đánh trúng Hồng Sam Tử, đòn đánh tạo ra vết máu hình đầu quỷ khuếch tán trên ngực, gây đòn chí mạng. Đại giá để thi triển thần thông này là ba giọt máu bổn mệnh.","nguon":["@c1429"],"congNang":["Ẩn thân trong cuồng phong hàn băng, biến thành bóng đỏ rồi hiện nguyên hình bất ngờ tấn công đối phương @c1429","Đánh trúng mục tiêu tạo vết máu hình đầu quỷ khuếch tán trên cơ thể, gây đòn chí mạng @c1429"],"tabs":{"tienTrinh":[{"chuong":"@c1429","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu xuất hiện và thi triển","text":"Tiên Phi nữ tử áo đỏ dùng ba giọt máu bổn mệnh hóa thành tam đầu quỷ ảnh, ẩn trong cuồng phong hàn băng đánh trúng đòn chí mạng Hồng Sam Tử.","anchor":"một trong những Tiên Phi đã lấy ba giọt máu bổn mệnh để hóa thành tam đầu quỷ ảnh"}]},"uyLuc":"Đánh trúng Hồng Sam Tử tạo vết máu hình đầu quỷ khuếch tán trên ngực, gây đòn chí mạng.","dacDiem":"Phải dùng ba giọt máu bổn mệnh làm đại giá để hóa thành; quỷ ảnh ẩn trong cuồng phong hàn băng, hình thái bóng đỏ trước khi hiện nguyên hình tấn công."},{"id":"khoi-doc-nam-mau-nam-chieu","name":"Khói độc năm màu","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Sánh ngang độc công Đại Hoang Thượng Nhân","hePhai":"Độc công","soHuu":["Nam Chiếu Thượng Nhân"],"blurb":"Độc tố bổn mạng của Nam Chiếu Thượng Nhân, khói độc năm màu thu thập luyện hóa cả vạn năm, ngưng tụ thành năm vòi rồng tấn công. Bị độc dịch Thiên Hoàng Lô nuốt sạch.","detail":"Độc tố bổn mạng của Nam Chiếu Thượng Nhân, luyện hóa thu thập cả vạn năm, uy lực sánh ngang độc công Đại Hoang Thượng Nhân. Khi thi triển biến ảo thành khói độc năm màu, ngưng tụ thành năm vòi rồng lao tới mục tiêu. Trong đại chiến Vân Hải bị ba giọt độc dịch Thiên Hoàng Lô của Vương Lâm nổ thành biển độc nuốt sạch và phản đòn tiêu diệt chủ nhân.","congNang":["Hóa thành năm vòi rồng khói độc tấn công đối phương"],"nguon":["@c1432"]},{"id":"que-tuong-to-tien-van-lac","name":"Quẻ tượng tổ tiên Vân Lạc","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Trường Tôn hội","soHuu":["Vân Lạc"],"blurb":"Quẻ tượng tiên tri do tổ tiên Vân Lạc đại ti truyền lại, mô tả chín tượng ứng nghiệm lần lượt khi thánh địa truyền thừa bị tấn công, hàm ý tiên tri về kết cục diệt vong của dòng tộc.","detail":"Quẻ tượng tổ tiên Vân Lạc là di sản tiên tri được tổ tiên Vân Lạc đại ti truyền lại cho hậu nhân, ghi chép chín giai đoạn hủy diệt sẽ ứng nghiệm khi thánh địa truyền thừa bị xâm phạm. Chín tượng bao gồm: tam tượng thiên lôi giáng, tứ tượng biển lửa thiêu, ngũ tượng đảo phân ly, lục tượng tổ hài vỡ, thất tượng phản tộc dung hồn, bát tượng thu lan niệm tổ, và cửu tượng chưa được đọc hết. Quẻ tượng ứng nghiệm từng bước khi Cực Cảnh của Vương Lâm tấn công thánh địa truyền thừa, được Vân Lạc đọc lại trong lúc đối mặt cuộc tấn công này (@c1433).","congNang":["Tiên tri diễn biến khi thánh địa truyền thừa bị tấn công, mô tả chín giai đoạn hủy diệt ứng nghiệm lần lượt (@c1433)"],"nguonGoc":"Tổ tiên Vân Lạc đại ti truyền lại","trangThai":"đã ứng nghiệm đến lục tượng","capNhatToi":"@c1433","tabs":{"tienTrinh":[{"chuong":"@c1433","loai":"xuất hiện","importance":"major","giaiDoan":"Ứng nghiệm đến lục tượng","text":"Vân Lạc đọc quẻ tượng tổ tiên khi bị Cực Cảnh tấn công thánh địa, từ tam tượng thiên lôi giáng đến lục tượng tổ hài vỡ đều ứng nghiệm. Cửu tượng chưa đọc hết thì thân thể đã vỡ tan.","anchor":"tam tượng thiên lôi giáng xuống.tứ tượng biển lửa thiêu đốt.ngũ tượng đảo nhỏ phân ly"}]},"nguon":["@c1433"]},{"id":"loi-dinh-vuong-lam","name":"Lôi đình","cn":"雷霆","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Thần thông phóng từ mắt phải Vương Lâm, tạo biển sấm sét vô tận quét diện rộng, tu sĩ bị tràn tới đều đồng loạt tan vỡ.","detail":"Vương Lâm phóng lôi đình vô tận từ mắt phải, tạo biển sấm sét bao phủ diện rộng. Tu sĩ giới ngoại bị sấm sét tràn tới đều đồng loạt tan vỡ, sức công phá diện rộng cực mạnh.","congNang":["Phóng lôi đình vô tận từ mắt phải tạo biển sấm sét quét diện rộng, tu sĩ bị tràn tới đều tan vỡ"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1434","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1434","loai":"thi triển","importance":"normal","giaiDoan":"Thi triển trong trận chiến chặn đại quân thứ ba","text":"Vương Lâm phóng lôi đình vô tận từ mắt phải tạo biển sấm sét, quét sạch tu sĩ giới ngoại xông vào lỗ hổng Phong Giới Đại Trận.","anchor":"lôi đồ trong mắt phải lóe lên, lôi đình vô tận từ xung quanh thân thể hắn nhanh chóng lao ra"}]},"nguon":["@c1434"]},{"id":"dai-tran-tu-chan-tinh-la-thien","name":"Đại trận tu chân tinh La Thiên","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"La Thiên","soHuu":["Lỗ Phu Tử"],"blurb":"Trận pháp do hơn chín trăm tu chân tinh La Thiên tạo thành, từng tu chân tinh hư ảo tràn ngập tinh không rơi xuống tiêu diệt tu sĩ giới ngoại.","detail":"Hơn chín trăm tu chân tinh hợp thành đại trận, từng tu chân tinh hư ảo tràn ngập tinh không, rơi xuống gây tiếng nổ ầm ầm tiêu diệt tu sĩ giới ngoại.","congNang":["Chín trăm tu chân tinh hợp trận, tu chân tinh hư ảo rơi từ tinh không tiêu diệt đối phương diện rộng"],"tabs":{"tienTrinh":[{"chuong":"@c1434","loai":"thi triển","importance":"normal","giaiDoan":"Triển khai trong trận chiến chi viện giới nội","text":"Hơn chín trăm tu chân tinh La Thiên triển khai đại trận, tu chân tinh hư ảo tràn ngập tinh không rơi xuống tiêu diệt tu sĩ giới ngoại.","anchor":"dưới đại trận do hơn chín trăm tu chân tinh tạo thành, từng trận tiếng ầm ầm vang vọng"}]},"nguon":["@c1434"]},{"id":"khai-thien-phu-than-thong","name":"Khai Thiên Phủ","cn":"开天斧","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Chiếc búa phóng to gấp ngàn vạn lần chiếm cứ tinh không, chém ra khe ngàn trượng xuyên qua đại quân, trọng thương cao thủ bước thứ ba và quét sạch vô số tu sĩ.","detail":"Vương Lâm vung Khai Thiên Phủ, chiếc búa lớn gấp ngàn vạn lần lao qua lỗ hổng Phong Giới Đại Trận, rạch một khe ngàn trượng xuyên qua đại quân tu sĩ bước thứ ba. Hai cao thủ bước thứ ba bị chém đứt một cánh tay mỗi người, hoảng sợ bỏ chạy. Vô số tu sĩ giới ngoại chết trong đường khe. Búa bay được hơn trăm vạn trượng mới tiêu tan.","nguon":["@c1435"]},{"id":"cung-phong-du","name":"Cây cung của Phong Dư","cn":"","loai":"khac","loaiLabel":"Pháp bảo (cung)","phamCap":"Không rõ","hePhai":"","soHuu":["Phong Dư"],"blurb":"Cây cung do Phong Dư — ngón cái, thủ đồ của Chưởng Tôn — sử dụng, giương lên nhắm bắn Vương Lâm qua lỗ hổng Phong Giới Đại Trận.","detail":"Phong Dư cầm cung giương lên nhắm bắn Vương Lâm từ phía Thái Cổ Tinh Thần qua lỗ hổng trận pháp chưa khép hết, sát khí tập trung lên mi tâm Vương Lâm. Vương Lâm nhận ra đã từng nhìn thấy cây cung này, ngụ ý lai lịch đặc biệt hoặc hai người đã từng chạm mặt trước đó.","nguon":["@c1435"]},{"id":"co-tuc-diep","name":"Cổ Tức Diệp","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật (phong ấn)","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Hơn mười lá cổ Tức Diệp tạo thành hơn mười tầng phong ấn bao vây mấy vạn tu sĩ giới ngoại, chặn không cho thoát.","detail":"Vương Lâm triệu hơn mười lá cổ Tức Diệp hình thành hơn mười tầng phong ấn bao vây tu sĩ giới ngoại đang tuyệt vọng xông về phía lỗ hổng, phối hợp cùng Hư hỏa để hoàn toàn phong tỏa đường rút lui.","nguon":["@c1435"]},{"id":"chu-chien","name":"Chữ Chiến","cn":"战","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lý tộc","soHuu":["Chiến lão quỷ"],"blurb":"Thần thông của Chiến lão quỷ, sử dụng ngón trỏ viết chữ \"Chiến\" giữa không trung để phá vỡ thuật pháp của đối phương. Được thi triển trong cuộc đối đầu với Chưởng Tôn, phá hủy ấn ký ánh trăng do thuật Giếng Trăng tạo ra.","detail":"Chữ Chiến là thần thông do Chiến lão quỷ thi triển. Khi sử dụng, thân ảnh giơ tay phải, ngón trỏ vung về phía trước viết ra chữ \"Chiến\" giữa hư không. Chữ viết mang lực lượng đủ sức phá vỡ ấn ký ánh trăng — sản phẩm của thuật Giếng Trăng do Chưởng Tôn vận dụng. Thần thông này xuất hiện trong cuộc giao tranh giữa Chiến lão quỷ và Chưởng Tôn (@c1438).","congNang":["Viết chữ \"Chiến\" giữa không trung bằng ngón trỏ, phá vỡ ấn ký ánh trăng của đối phương (@c1438)"],"tabs":{"tienTrinh":[{"chuong":"@c1438","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Chiến lão quỷ giơ ngón trỏ viết chữ Chiến phá vỡ ấn ký ánh trăng của Chưởng Tôn.","anchor":"giơ tay phải lên, ngón trỏ vung về phía trước, bất ngờ liền viết ra một chữ Chiến"}]},"nguon":["@c1438"],"uyLuc":"Phá vỡ được ấn ký ánh trăng do thuật Giếng Trăng của Chưởng Tôn tạo ra (@c1438).","dacDiem":"Thi triển bằng ngón trỏ tay phải, vung viết thành chữ \"Chiến\" giữa hư không."},{"id":"thuat-gieng-trang","name":"Thuật Giếng Trăng","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Thái Cổ Ngũ Tôn","soHuu":["Chưởng Tôn"],"blurb":"Thuật Giếng Trăng là thần thông của Chưởng Tôn, triệu hồi một cái giếng khổng lồ chứa ánh trăng, từ đó mò lên thứ nửa nước giếng nửa ánh trăng để tấn công đối phương bằng ấn ký xuyên thấu.","detail":"Khi thi triển, Chưởng Tôn bấm quyết triệu hồi phía sau một cái giếng rất lớn có ánh trăng chiếu rọi. Chưởng Tôn nhúng tay trái vào giếng, mò lên thứ không phân biệt được là nước giếng hay ánh trăng, rồi vung ra phía trước. Nước giếng bốc hơi khi chạm tu chân tinh, nhưng ấn ký hình ánh trăng vẫn xuyên qua tu chân tinh bay tiếp để tấn công. Tại @c1438, Chưởng Tôn thi triển thuật này nhắm phá tu chân tinh thứ chín, tuy nhiên ấn ký bị Chiến ngăn lại.","congNang":["Triệu hồi giếng trăng khổng lồ phía sau người thi triển @c1438","Nhúng tay vào giếng mò lên chất thể nửa nước giếng nửa ánh trăng để vung ra tấn công @c1438","Tạo ấn ký hình ánh trăng có khả năng xuyên thấu qua tu chân tinh @c1438"],"tabs":{"tienTrinh":[{"chuong":"@c1438","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Chưởng Tôn triệu hồi giếng trăng, nhúng tay mò ánh trăng ném ra phá tu chân tinh thứ chín nhưng ấn ký bị Chiến lão quỷ phá.","anchor":"Hắn đem ánh trăng ở dưới giếng đột nhiên mò lên, không thể phân biệt rõ hắn mò lên nước giếng hay là ánh trăng"}]},"nguon":["@c1438"],"uyLuc":"Ấn ký ánh trăng có thể xuyên qua tu chân tinh, phần nước giếng bốc hơi khi va chạm nhưng ấn ký vẫn bay tiếp tấn công mục tiêu phía sau @c1438.","dacDiem":"Thần thông kết hợp hai yếu tố nước giếng và ánh trăng; phần nước bốc hơi khi gặp chướng ngại nhưng ấn ký ánh trăng ẩn bên trong vẫn xuyên thấu tiếp tục, tạo thành đòn tấn công hai lớp khó phòng bị."},{"id":"bach-van-tu-linh-an","name":"Bách Vạn Tu Linh Ấn","cn":"百万修灵印","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Thất Thải Đạo Nhân"],"blurb":"Bách Vạn Tu Linh Ấn là ấn pháp từng đặt trên Thất Thải Đạo Nhân, bị chính hắn chủ động phá vỡ. Chiến lão quỷ xác nhận việc phá ấn này chính là điều hắn chờ đợi, và đây là cơ hội thứ ba cũng là lần cuối cùng dành cho Thất Thải Đạo Nhân.","detail":"Bách Vạn Tu Linh Ấn gắn liền với Thất Thải Đạo Nhân; tại thời điểm được đề cập, ấn pháp này đã bị chính Thất Thải Đạo Nhân chủ động phá vỡ. Chiến lão quỷ khi chứng kiến sự kiện đó đã tiết lộ rằng đây chính là điều hắn đang chờ đợi, đồng thời nhấn mạnh đây là cơ hội thứ ba và cũng là cơ hội cuối cùng của Thất Thải Đạo Nhân. Nguồn gốc cụ thể của ấn pháp, ai đặt ra, cùng cơ chế hoạt động chi tiết chưa được tiến trình hiện có làm rõ.","congNang":["Phong ấn hoặc khống chế đối tượng mang ấn — thể hiện qua việc ấn được đặt trên Thất Thải Đạo Nhân và cần chủ động phá vỡ mới thoát khỏi @c1439"],"nguoiTu":[{"ten":"Thất Thải Đạo Nhân","tuChuong":"@c1439","tangDatToi":"","trangThai":"da-pha-vo"}],"tabs":{"tienTrinh":[{"chuong":"@c1439","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Bị Thất Thải Đạo Nhân chủ động phá vỡ","text":"Chiến lão quỷ tiết lộ Thất Thải Đạo Nhân chủ động phá vỡ Bách Vạn Tu Linh Ấn, đây là cơ hội thứ ba và cuối cùng.","anchor":"Bách Vạn Tu Linh Ấn. không ngờ ngươi chủ động phá vỡ ấn này, lão phu chính là đang chờ điều này"}]},"nguon":["@c1439"],"dacDiem":"Ấn pháp có thể bị chính người mang ấn chủ động phá vỡ, và việc phá ấn mang tính chất không thể đảo ngược — Chiến lão quỷ xác nhận đây là cơ hội thứ ba và cuối cùng, ngụ ý giới hạn số lần có thể phá ấn hoặc số lần cơ hội liên quan đến hành động này."},{"id":"that-thai-thuat","name":"Thất Thải Thuật","cn":"七彩术","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Người điên"],"blurb":"Thần thông của tu sĩ điên trong Thất Thải Giới, ánh sáng bảy màu hình thành bánh xe rất lớn ầm ầm chuyển động.","detail":"Tu sĩ điên thi triển, ánh sáng bảy màu hình thành bánh xe lớn chuyển động. Nhìn hoành tráng nhưng thực tế không có uy lực, chạm thi thể liền tiêu tan. Tên gọi gợi liên hệ với Thất Thải Giới.","congNang":["Triệu hoán bánh xe bảy sắc tấn công"],"nguoiTu":[{"ten":"Người điên","tuChuong":"@c1441","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1441","loai":"thi triển","importance":"normal","giaiDoan":"Tu sĩ điên thi triển trong Thất Thải Giới","text":"Tu sĩ điên thi triển Thất Thải Thuật, ánh sáng bảy màu hình thành bánh xe lớn ầm ầm chuyển động, nhìn hoành tráng nhưng không có uy lực thực tế.","anchor":"ngươi hãy xem Thất Thải Thuật của bổn vương"}]},"nguon":["@c1441"]},{"id":"an-ky-quy-di-nguoi-dien","name":"Ấn ký quỷ dị (của người điên)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Người điên"],"blurb":"Ấn ký hiện trên tay phải người điên, dùng vỗ vào ngực để cưỡng ép phun ra máu tươi tinh thuần từ bản thân.","detail":"Người điên giơ tay phải, ấn ký quỷ dị hiện lên, vỗ trực tiếp vào ngực mình ép xuất huyết tinh hoa. Máu phun ra màu vàng nồng đậm, tinh thuần tới cực điểm.","congNang":["Cưỡng ép xuất huyết tinh hoa từ bản thân, phun ra máu tinh thuần màu vàng nồng đậm"],"nguoiTu":[{"ten":"Người điên","tuChuong":"@c1442","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1442","loai":"thi triển","importance":"normal","giaiDoan":"Người điên thi triển ép phun máu cứu Vương Lâm","text":"Người điên dùng ấn ký quỷ dị trên tay phải vỗ vào ngực, phun ra máu vàng nồng đậm tinh thuần nhiều lần liên tiếp, cuối cùng phun cả bổn mệnh huyết.","anchor":"trên tay phải hắn đột nhiên có một ấn ký quỷ dị hiện lên. Ấn ký này trực tiếp vỗ lên thân thể hắn"}]},"nguon":["@c1442"]},{"id":"tam-an-to-tien-tien-toc","name":"Tam ấn tổ tiên Tiên Tộc","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ (bí thuật tổ tiên Tiên Tộc)","hePhai":"Tiên Tộc","soHuu":["Người điên","Vương Lâm"],"blurb":"Bí thuật ấn pháp truyền thừa từ tổ tiên Tiên Tộc, gồm ba ấn có thể biến thân thể thành bất diệt. Khẩu quyết lưu truyền: một ấn thay đổi trời, hai ấn thay đổi đạo, ấn thứ ba đã bị thất truyền do người điên quên mất.","detail":"Tam ấn tổ tiên Tiên Tộc là ấn pháp cổ xưa có nguồn gốc từ tổ tiên Tiên Tộc, mang khí tức hỗn tạp tựa hồ tồn tại từ thuở thiên địa sơ khai. Ấn ký có hình tròn, khi kích hoạt sẽ hiện trên thân thể. Khẩu quyết tương truyền: \"Thiên địa sơ khai, tổ tiên giáng trần, tam ấn biến đổi thế giới, trở thành biểu tượng Tiên Tộc — Một ấn thay đổi trời, Hai ấn thay đổi đạo, Ba ấn thay đổi…\" — phần nội dung ấn thứ ba đã bị người điên quên mất. Ấn pháp này thuộc loại cấm truyền ngoại tộc; ca ca của người điên từng nghiêm cấm không được truyền cho người ngoài Tiên Tộc, đặc biệt là ba bộ tộc thuộc Cổ Quốc, vì sẽ gây phiền toái lớn — song người điên đã bỏ qua lời dặn này. Khi ấn lên mi tâm người mang truyền thừa Cổ Thần như Vương Lâm, sức mạnh Đạo Cổ trong thân phản kháng dữ dội. Người điên đã nhớ lại tam ấn ","thuocTinh":"Tiên lực (tổ tiên Tiên Tộc)","nguonGoc":"Tổ tiên Tiên Tộc","dacDiem":"Ấn ký hình tròn mang khí tức sơ khai từ thuở thiên địa hỗn mang; thuộc loại cấm truyền ngoại tộc, đặc biệt nghiêm cấm truyền cho ba bộ tộc Cổ Quốc; khi ấn lên người mang truyền thừa Cổ Thần sẽ bị sức mạnh Đạo Cổ phản kháng dữ dội.","congNang":["Biến thân thể thành bất diệt của Tiên Tộc","Ấn thứ nhất có thể thay đổi trời @c1443","Ấn thứ hai có thể thay đổi đạo @c1443"],"nguoiTu":[{"ten":"Người điên","tuChuong":"@c1443","tangDatToi":"Sở hữu gốc","trangThai":"da-truyen"},{"ten":"Vương Lâm","tuChuong":"@c1443","tangDatToi":"Nhận ấn ký","trangThai":"moi-nhan"}],"tabs":{"tienTrinh":[{"chuong":"@c1443","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Người điên nhớ ra và truyền cho Vương Lâm","text":"Người điên tự giật đứt cánh tay trái, khi gắn lại thấy ấn ký hình tròn sơ khai hiện ra, nhờ đó nhớ ra tam ấn tổ tiên. Bấm quyết khiến tu chân tinh chấn động, rút ấn ký trên mi tâm đặt lên tinh điểm Cổ Thần trên mi tâm Vương Lâm. Tuyên bố tam ấn tổ tiên biến thành thân thể bất diệt Tiên Tộc. Sức mạnh Cổ Thần từ thân Vương Lâm phản kháng dữ dội, đánh người điên bắn tung.","anchor":"Tam ấn của tổ tiên biến thành thân thể bất diệt của Tiên Tộc"}]},"capNhatToi":"@c1443","dinhDanh":"goc","nguon":["@c1443"]},{"id":"tien-nhan-bat-diet-the","name":"Tiên Nhân Bất Diệt Thể","cn":"仙人不灭体","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Tiên tộc","soHuu":["Vương Lâm"],"blurb":"Tiên Nhân Bất Diệt Thể là thân thể bất diệt có nguồn gốc từ ấn ký tiên tổ truyền thừa, tự tái tạo từ máu thịt nhờ tiên khí và bất diệt trước phá hủy vật lý. Tại mốc hiện tại, ấn ký kích hoạt khi tinh điểm Cổ Thần vỡ tan, tiên thể trong suốt ngưng tụ qua bảy lần toái tinh. (+) Thể chất bất diệt của tiên nhân, thân thể tan vỡ rồi tự ngưng tụ nhờ kim quang, không thể bị giết. Vương Lâm đạt một nửa nhờ người điên, chưa hoàn chỉnh. [CAN-SOAT-GOP]","detail":"Tiên Nhân Bất Diệt Thể bắt nguồn từ ấn ký tiên tổ truyền thừa. Khi thân Cổ Thần tan vỡ, tiên khí ngưng tụ tái tạo tiên thể trong suốt, máu tiên từ xương tủy lưu chuyển khắp thân; nguyên tiên — nguyên thần tiên nhân thật sự — hiện ra khi tiên thể ngưng tụ. Công pháp này xung đột trực tiếp với Cổ Thần lực và Đạo Cổ lực: nếu không có truyền thừa Đạo Cổ vương tộc, người nhận ấn ký sẽ mất truyền thừa Cổ Thần, thành tiên nhân rồi vỡ tan mà chết. Tại chương 1444, ấn ký tiên tổ kích hoạt, tiên thể trong suốt ngưng tụ mỗi khi tinh điểm Cổ Thần vỡ tan; quá trình diễn ra qua bảy lần toái tinh.","thuocTinh":"Tiên khí","nguonGoc":"Ấn ký tiên tổ truyền thừa","congNang":["Tự tái tạo thân thể từ máu thịt nhờ tiên khí @c1444","Bất diệt trước phá hủy vật lý @c1444","Nguyên tiên hiện ra khi tiên thể ngưng tụ @c1444","Tiên thể trong suốt ngưng tụ mỗi khi tinh điểm Cổ Thần vỡ tan @c1444"],"dacDiem":"Xung đột trực tiếp với Cổ Thần lực và Đạo Cổ lực; cần truyền thừa Đạo Cổ vương tộc mới tồn tại song song. Tiên thể ngưng tụ qua bảy lần toái tinh khi ấn ký tiên tổ kích hoạt.","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1444","tangDatToi":"","trangThai":"dung-hop-voi-co-than"}],"tabs":{"tienTrinh":[{"chuong":"@c1444","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu hiện hình trên thân Vương Lâm","text":"Ấn ký tiên tổ kích hoạt, tiên thể trong suốt ngưng tụ mỗi khi tinh điểm Cổ Thần vỡ tan. Sau bảy lần toái tinh và đệ nhị tổn xuất hiện, tiên thể cùng Cổ Thần lực triệt tiêu lẫn nhau, cuối cùng được Thiên Nghịch dung hợp thành nhất thể.","anchor":"Thân thể bất diệt này đến từ ấn ký của tiên tổ, chính vì có ấn ký này mà khiến cho Vương Lâm có thể có thể được thân thể bất diệt kia"}]},"capNhatToi":"@c1444","nguon":["@c1444","@c1488","@c1536"]},{"id":"de-nhi-ton-tam-ton-that-kiep","name":"Đệ nhị tổn (tam tổn thất kiếp Cổ Thần)","cn":"","loai":"khac","loaiLabel":"Kiếp nạn","phamCap":"Không rõ","hePhai":"Cổ Thần","soHuu":[],"blurb":"Đệ nhị tổn là kiếp nạn thứ hai trong tam tổn thất kiếp của Cổ Thần, bộc phát sau khi bảy tinh điểm đã vỡ hết và trải qua lần chuyển đổi Cổ Thần thể – Tiên thể thứ tám. Do bị ấn ký tiên tổ kích động, kiếp nạn này xuất hiện sớm hơn thời điểm bình thường.","detail":"Đệ nhị tổn xuất hiện tại mốc bảy tinh điểm đã tan vỡ hoàn toàn và sau tám lần chuyển đổi qua lại giữa Cổ Thần thể và Tiên thể. Sự hiện diện của ấn ký tiên tổ đã dẫn dắt và kích động kiếp nạn này bộc phát sớm hơn so với tiến trình thông thường. Khi đệ nhị tổn giáng xuống, sức mạnh của nó cùng lực tan vỡ vốn có của Cổ Thần đối chọi lại tiên thể đang trong quá trình thành hình, hai bên triệt tiêu lẫn nhau, qua đó bảo vệ truyền thừa Cổ Thần không bị tiên thể nuốt mất.","congNang":["Phá hủy tiên thể đang thành hình, ngăn tiên thể hoàn chỉnh thay thế Cổ Thần thể @c1444","Bảo vệ truyền thừa Cổ Thần bằng cách cùng sức mạnh tan vỡ Cổ Thần triệt tiêu lẫn nhau với tiên thể @c1444"],"dacDiem":"Bị ấn ký tiên tổ kích động mà xuất hiện sớm hơn bình thường, bộc phát sau khi bảy tinh điểm vỡ hết và trải qua lần chuyển đổi thứ tám giữa Cổ Thần thể và Tiên thể.","tabs":{"tienTrinh":[{"chuong":"@c1444","loai":"xuất hiện","importance":"major","giaiDoan":"Đệ nhị tổn bộc phát","text":"Sau bảy tinh điểm vỡ hết và lần chuyển đổi thứ tám, đệ nhị tổn trong tam tổn thất kiếp Cổ Thần xuất hiện do ấn ký tiên tổ dẫn dắt, cùng Cổ Thần lực đối chọi tiên thể.","anchor":"đệ nhị tổn trong tam tổn thất kiếp của Cổ Thần đã xuất hiện"}]},"capNhatToi":"@c1444","nguon":["@c1444"]},{"id":"cuu-khuc-tam-tuong","name":"Cửu khúc tam tướng","cn":"九曲三相","loai":"khac","loaiLabel":"Hiện tượng tiên tộc","phamCap":"Không rõ","hePhai":"Tiên tộc","soHuu":[],"blurb":"Truyền thuyết về biểu hiện khi tiên tổ/cổ Tổ giáng trần: tám tướng là tiên, cửu khúc là cổ. Đệ nhất tượng (lưỡng khúc) là ngân mục kim thân. (+) Hiện tượng liên quan tiên tổ giáng lâm; đệ nhất tướng là cảnh bầu trời vàng mặt đất đen (kim thiên hắc địa). [CAN-SOAT-GOP] (+) Thiên địa dị tượng gắn với lúc Tiên Tổ và Cổ Tổ sinh ra, gồm Cửu Khúc và Tam Tướng. Trên Cổ Đạo Sơn, dị tượng này lần lượt hiện trên người Vương Lâm trong quá trình Tiên Cổ dung hợp. [CAN-SOAT-GOP]","detail":"Người điên nhận ra cảnh tượng kim thiên hắc địa do Vương Lâm tạo ra chính là đệ nhất tướng trong cửu khúc tam tướng, giống y cảnh khi tiên tổ giáng lâm năm xưa. Còn hai tướng nữa chưa rõ.","congNang":["Đệ nhất tướng: bầu trời vàng mặt đất đen (kim thiên hắc địa)"],"tabs":{"tienTrinh":[{"chuong":"@c1444","loai":"nhắc tới","importance":"normal","giaiDoan":"Người điên nhận ra đệ nhất tướng","text":"Người điên nhận ra cảnh kim thiên hắc địa là đệ nhất tướng trong cửu khúc tam tướng, giống khi tiên tổ giáng lâm năm xưa.","anchor":"năm đó khi tiên tổ giáng lâm, đã xuất hiện đệ nhất tướng trong cửu khúc tam tướng"}]},"capNhatToi":"@c1444","nguon":["@c1444","@c1682","@c1913"]},{"id":"tam-dai-vuong-tinh","name":"Tam đại vương tính","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Cổ quốc bí truyền","hePhai":"Cổ quốc","soHuu":["Vương Lâm"],"blurb":"Tam đại vương tính là bí truyền hiếm gặp của Cổ Quốc, kết hợp ba dòng lực Thần, Ma và Yêu thành một thể thống nhất. Vương Lâm được người điên nhận định đang thực hiện pháp môn này khi dung hợp sáu ma tinh Cổ Ma vào mắt phải cùng kim quang Cổ Thần.","detail":"Tam đại vương tính là bí truyền của Cổ Quốc, lấy ba dòng lực Thần, Ma, Yêu làm nền tảng. Theo lời người điên, Cổ Quốc có ba đại tính: cực cổ lấy Yêu làm gốc, sau đó đến Ma, và Thần. Trong cách vận dụng của Vương Lâm, Cổ Thần đóng vai trò bổn tôn, Cổ Ma đóng vai trò phân thân. Tại chương @c1445, người điên chứng kiến Vương Lâm dung hợp sáu ma tinh Cổ Ma vào mắt phải kết hợp với kim quang Cổ Thần, từ đó nhận ra hắn đang thực hiện tam đại vương tính. Đây được xem là bí truyền cổ quốc hiếm gặp, ít người biết đến.","nguonGoc":"Cổ quốc","dacDiem":"Kết hợp ba dòng lực: Thần (bổn tôn), Ma (phân thân), Yêu (cực cổ gốc)","congNang":["Kết hợp ba dòng lực Thần, Ma, Yêu thành một thể thống nhất","Dung hợp ma tinh Cổ Ma vào thân thể (mắt phải) cùng kim quang Cổ Thần @c1445"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1445","tangDatToi":"Đang tiến hành (Thần + Ma, thiếu Yêu)","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1445","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Người điên nhận diện","text":"Người điên chứng kiến Vương Lâm dung hợp sáu ma tinh Cổ Ma vào mắt phải kết hợp kim quang Cổ Thần, nhận ra đây là tam đại vương tính trong cổ quốc.","anchor":"Lấy Cổ Thần làm bổn tôn, Cổ Ma làm phân thân. Đây chính là tam đại vương tính trong cổ quốc"}]},"nguon":["@c1445"]},{"id":"bat-diet-the","name":"Bất diệt thể","cn":"","loai":"khac","loaiLabel":"Thể chất đặc thù","phamCap":"Tiên tộc bí bảo","hePhai":"Tiên tộc","soHuu":["Vương Lâm","Người điên"],"blurb":"Bất diệt thể là một thể chất cực kỳ hiếm có thuộc tiên tộc, được biết đến chỉ có hai người sở hữu là người điên và ca ca của hắn. Vương Lâm dù là tu sĩ cổ quốc cũng có được thể chất này, khiến người điên vô cùng kinh ngạc và quyết tâm truy xét nguồn gốc.","detail":"Bất diệt thể là một loại thể chất đặc thù của tiên tộc, tính tới mốc hiện tại được xác nhận là cực kỳ hiếm, trong toàn bộ tiên tộc chỉ có người điên cùng ca ca của hắn sở hữu. Khi người điên phát hiện Vương Lâm — vốn rõ ràng mang huyết thống tiên tộc nhưng lại có thân phận tu sĩ cổ quốc — cũng có bất diệt thể, hắn hết sức chấn động. Điều này dẫn tới nghi vấn ai đã trao bảo vật hoặc phương pháp đắc thể chất này cho một tu sĩ cổ quốc, và người điên quyết tâm điều tra sự việc. Nguồn gốc cụ thể cũng như cơ chế hình thành bất diệt thể chưa được tiến trình hiện có làm rõ thêm. @c1445","nguonGoc":"Tiên tộc","dacDiem":"Thể chất cực hiếm của tiên tộc, trong toàn bộ tiên tộc được biết chỉ có hai anh em người điên sở hữu; việc một tu sĩ cổ quốc như Vương Lâm có được là hiện tượng dị thường đủ gây chấn động.","congNang":["Cơ thể bất diệt — chi tiết cụ thể về biểu hiện và giới hạn chưa được tiến trình hiện có làm rõ @c1445"],"nguoiTu":[{"ten":"Người điên","tuChuong":"@c1445","tangDatToi":"","trangThai":"da-co"},{"ten":"Vương Lâm","tuChuong":"@c1445","tangDatToi":"","trangThai":"da-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1445","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Người điên xác nhận Vương Lâm có bất diệt thể","text":"Người điên phát hiện Vương Lâm sở hữu bất diệt thể vốn chỉ hắn và ca ca có, thắc mắc tại sao tu sĩ cổ quốc lại có thể chất tiên tộc.","anchor":"rõ ràng hắn là người tiên tộc ta, nhưng lại có được bất diệt thể mà chỉ có ta và ca ca ta có"}]},"nguon":["@c1445"]},{"id":"nam-dao-bon-nguyen","name":"Năm đạo bổn nguyên","cn":"","loai":"cong-phap","loaiLabel":"Hệ thống tu luyện","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Năm đạo bổn nguyên là hệ thống gồm sinh tử, nhân quả, thật giả và hai đạo chưa được nhắc tên. Khi cả năm đạo đại thành, ngũ chỉ đầy đủ, tu sĩ có thể mở không môn và chính thức bước vào bước thứ ba.","detail":"Vương Lâm suy luận rằng trong năm đạo bổn nguyên, sinh tử, nhân quả và thật giả là ba đạo khó nhất. Nếu ba đạo này đại thành, chúng có thể phối hợp hóa giải lực bài xích giữa nguyên tiên và Cổ Thần: bổn nguyên sinh tử chia lực bài xích thành hai luồng sinh tử, bổn nguyên nhân quả tạo tuần hoàn giữa hai luồng đó, và bổn nguyên thật giả lừa khiến lực nguyên tiên cùng Cổ Thần dung hợp thay vì bài xích. Khi toàn bộ năm đạo bổn nguyên đại thành, ngũ chỉ đầy đủ, tu sĩ có thể mở không môn, chính thức trở thành tu sĩ bước thứ ba. Hai đạo bổn nguyên còn lại chưa được nhắc tên trong tiến trình hiện có.","thuocTinh":"bổn nguyên","nguonGoc":"","yeuCau":"Đại thành từng đạo, cần đạo quả","uyLuc":"Hóa giải lực bài xích giữa nguyên tiên và Cổ Thần, mở không môn để chính thức bước vào bước thứ ba","dacDiem":"Ba đạo khó nhất trong năm là sinh tử, nhân quả và thật giả; hai đạo còn lại chưa được nhắc tên","congNang":["Bổn nguyên sinh tử chia lực bài xích giữa nguyên tiên và Cổ Thần thành hai luồng sinh tử @c1446","Bổn nguyên nhân quả tạo tuần hoàn giữa hai luồng sinh tử, duy trì cân bằng @c1446","Bổn nguyên thật giả lừa khiến lực nguyên tiên và Cổ Thần dung hợp thay vì bài xích @c1446","Năm đạo đại thành khiến ngũ chỉ đầy đủ, mở không môn, bước vào bước thứ ba @c1446"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1446","tangDatToi":"Chưa đại thành ba đạo khó nhất","trangThai":"đang tu"}],"cacTang":[{"ten":"Sinh tử","moTa":"Chia lực bài xích thành hai luồng sinh tử","chuong":"@c1446"},{"ten":"Nhân quả","moTa":"Tạo tuần hoàn giữa hai luồng sinh tử","chuong":"@c1446"},{"ten":"Thật giả","moTa":"Lừa lực bài xích khiến nguyên tiên và Cổ Thần lực dung hợp","chuong":"@c1446"}],"tabs":{"tienTrinh":[{"chuong":"@c1446","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Vương Lâm lĩnh ngộ lộ trình đại thành","text":"Vương Lâm suy luận ra cách dùng ba bổn nguyên sinh tử, nhân quả, thật giả để hóa giải lực bài xích, xác định năm đạo đại thành sẽ mở không môn bước vào bước thứ ba.","anchor":"Năm đạo bổn nguyên đại thành như vậy có thể khiến cho ngũ chỉ của ta đầy đủ, có thể mở ra không môn, chính thức trở thành tu sĩ bước thứ ba"}]},"capNhatToi":"@c1446","nguon":["@c1446"]},{"id":"toai-thien-nhat-cung","name":"Toái Thiên Nhất Cung","aliases":["Thuật bắn tên"],"loai":"than-thong","loaiLabel":"Đạo thuật","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Người điên"],"blurb":"Đạo thuật bắn tên do người điên biểu diễn, tư thế giương cung giống hệt Lý Quảng, phóng ra luồng khí sắc bén có thể bắn nát thiên địa.","detail":"Người thi triển bắt quyết tạo thế giương cung bắn tên, phóng ra luồng khí sắc bén cực mạnh. Chỉ cần buông tay là thiên địa bị bắn nát.","congNang":["Phóng luồng khí sắc bén có thể bắn nát thiên địa"],"tabs":{"tienTrinh":[{"chuong":"@c1448","loai":"thi triển","importance":"normal","giaiDoan":"Người điên biểu diễn cho Vương Lâm xem","text":"Người điên bắt quyết tạo thế giương cung bắn tên giống tư thế Lý Quảng, phóng ra luồng khí sắc bén có thể bắn nát thiên địa.","anchor":"giống như chỉ cần buông tay là lập tức thiên địa sẽ bị một mũi bắn nát"}]},"nguon":["@c1448"]},{"id":"thuat-bay-mau","name":"Thuật bảy màu","aliases":["Thuật thương bảy màu"],"loai":"than-thong","loaiLabel":"Đạo thuật","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Người điên"],"blurb":"Đạo thuật triệu hồi ánh sáng bảy màu (Xích, Chanh, Hoàng, Lục, Thanh, Lam, Tử) ngưng tụ thành cây thương, ẩn chứa lực lượng tâm tình vượt xa hư hỏa.","detail":"Ánh sáng bảy màu ngưng tụ thành cây thương, ảnh hưởng tâm trí người chứng kiến. Lực lượng tâm tình vượt xa hư hỏa, khiến Vương Lâm toát mồ hôi lạnh khi quan sát.","congNang":["Ngưng tụ ánh sáng bảy màu thành thương, xé tan tinh không","Ẩn chứa lực lượng tâm tình ảnh hưởng tâm trí người chứng kiến, vượt xa hư hỏa"],"tabs":{"tienTrinh":[{"chuong":"@c1448","loai":"thi triển","importance":"normal","giaiDoan":"Người điên biểu diễn cho Vương Lâm xem","text":"Người điên triệu hồi ánh sáng bảy màu ngưng tụ thành cây thương, ẩn chứa lực lượng tâm tình vượt xa hư hỏa, ảnh hưởng tâm trí Vương Lâm.","anchor":"Ánh sáng bảy màu này ẩn chứa một lực lượng tâm tình, vừa xuất hiện đã giống như có thể ảnh hướng tới tất cả những người chứng kiến"}]},"nguon":["@c1448"]},{"id":"tien-chi-cuu-tuyet","name":"Tiên Chi Cửu Tuyệt","cn":"仙之九絕","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ (vương tộc người điên)","soHuu":[],"blurb":"Tiên Chi Cửu Tuyệt là hệ thống thần thông bí ẩn gồm chín tuyệt, được người điên vô ý buột miệng nhắc đến khi Vương Lâm hỏi về thần thông mạnh nhất. Ngay cả ca ca của người điên cũng chỉ lĩnh ngộ được tới Thất Tuyệt, và trong cơ thể người điên tồn tại lời thề cấm tiết lộ chi tiết, vi phạm sẽ chịu tiên phạt.","detail":"Tiên Chi Cửu Tuyệt xuất hiện lần đầu khi người điên buột miệng hé lộ tên gọi trước câu hỏi của Vương Lâm về thần thông mạnh nhất (@c1450). Theo lời người điên, đây là một hệ thống gồm chín tuyệt — song hắn lập tức ôm miệng ngừng lại, giải thích rằng trong cơ thể mình tồn tại lời thề: nếu tiết lộ chi tiết sẽ bị tiên phạt. Người điên cũng cho biết ca ca của hắn chỉ hiểu ra được tới Thất Tuyệt, ngụ ý rằng toàn bộ Cửu Tuyệt cực kỳ khó lĩnh ngộ. Nội dung cụ thể, từng tuyệt riêng lẻ cùng uy lực thực sự của Tiên Chi Cửu Tuyệt chưa được hé lộ tính tới mốc hiện tại.","dacDiem":"Có lời thề cấm tiết lộ, vi phạm chịu tiên phạt. Ca ca người điên chỉ lĩnh ngộ được tới Thất Tuyệt, cho thấy mức độ thâm áo cực cao của hệ thống chín tuyệt này (@c1450).","cacTang":[],"congNang":[],"nguoiTu":[],"tabs":{"tienTrinh":[{"chuong":"@c1450","loai":"xuat-hien","importance":"major","giaiDoan":"Lần đầu được nhắc đến","text":"Người điên buột miệng hé lộ tên Tiên Chi Cửu Tuyệt khi Vương Lâm hỏi thần thông mạnh nhất. Ca ca người điên chỉ hiểu được Thất Tuyệt. Trong cơ thể người điên có lời thề cấm tiết lộ chi tiết.","anchor":"Tiên Chi Cửu Tuyệt ngay cả ca ca ta cũng chỉ hiểu ra được có Thất Tuyệt"}]},"nguon":["@c1450"]}]};